def generate_service_order_id(prefix: str = "AGM") -> str:
    """رقم طلب بسيط لخدمات تيليغرام ."""
    now = datetime.now()
    return f"{prefix}-{now.strftime('%Y%m%d-%H%M%S')}"

def telegram_contact_url(message: str = "") -> str:
    """رابط تيليغرام مباشر مع محاولة تمرير نص جاهز عند دعم التطبيق لذلك."""
    username = (TELEGRAM_USERNAME or "Astrol25").strip().lstrip("@")
    if not message:
        return f"https://t.me/{username}"
    return f"https://t.me/{username}?text={urllib.parse.quote(message)}"

def make_report_user_facing(text: str) -> str:
    """ينظف التقرير المعروض من التفاصيل الفنية الخام مع إبقاء الأثر العملي للقارئ."""
    if not text:
        return ""
    cleaned_lines = []
    skip_markers = [
        "التقرير الفني للباحث", "التقرير الفني للمطور", "مخصص للمراجعة الفنية",
        "المجموع الرقمي", "technical", "technical_notes", "كود", "JD", "UT",
        "خط العرض", "خط الطول", "فرق التوقيت", "خريطة العبور", "خريطة الميلاد",
        "مواقع الكواكب", "الأسباب الفلكية", "درجة:", "الدرجة:", "الفارق",
        "ضمن أورب", "الأورب", "orb", "ملاحظة فنية",
        "الدعم:", "التحذيرات:", "أقوى التفعيلات", "نوع الدلالة", "المحور:",
        "العابر", "عبور", "تفعيل", "حاكم البيت", "البروفكشن", "الفريدار",
        "حد بطليموس", "درجة التفعيل", "الهدف:", "نوعية الحد", "الأورب",
    ]
    for raw in str(text).splitlines():
        line = raw.strip()
        if not line:
            if cleaned_lines and cleaned_lines[-1] != "":
                cleaned_lines.append("")
            continue
        if any(m in line for m in skip_markers):
            continue
        if re.search(r"\d{1,3}°|\d+\.\d+|\b(?:البيت|الدرجة)\s*\d+", line):
            continue
        line = re.sub(r"\([^\)]*[A-Za-z_][^\)]*\)", "", line)
        line = re.sub(r"\b\d{1,3}°\d{0,2}′?\s*(?:الحمل|الثور|الجوزاء|السرطان|الأسد|العذراء|الميزان|العقرب|القوس|الجدي|الدلو|الحوت)?", "", line)
        line = re.sub(r"\b\d+(?:\.\d+)?\s*°", "", line)
        line = re.sub(r"\s{2,}", " ", line).strip(" -،:")
        if not line or line in {"=", "-"} or set(line) <= {"=", "-", " "}:
            continue
        cleaned_lines.append(line)
    cleaned = "\n".join(cleaned_lines).strip()
    cleaned = cleaned.replace("تقرير المستخدم", "خلاصة التأثير")
    cleaned = cleaned.replace("التقرير الفني", "التقرير الاحترافي")
    return cleaned


def _extract_forecast_value(raw: str, label: str) -> str:
    try:
        m = re.search(label + r"\s*[:：]\s*([^\n]+)", raw)
        return m.group(1).strip() if m else ""
    except Exception:
        return ""


def _forecast_topic_ar(raw_topic: str) -> str:
    raw = (raw_topic or "").strip()
    mapping = {
        "marriage": "الزواج والخطوبة",
        "love": "الحالة العاطفية",
        "return": "عودة العلاقة أو التواصل",
        "career": "العمل والمهنة",
        "money": "المال والاستثمار",
        "travel": "السفر والهجرة",
        "study": "الدراسة والاختبارات",
        "health": "الصحة والعملية الجراحية",
        "general": "السياق العام",
    }
    for k, v in mapping.items():
        if k in raw or v in raw:
            return v
    return raw or "الموضوع المختار"


def _practical_premium_forecast_report(free_text: str, technical_text: str = "") -> str:
    """يبني تقرير التوقعات الاحترافي من جديد بلغة تأثيرية فقط، دون عرض طبقات الحساب."""
    raw = str(technical_text or "")
    base = make_report_user_facing(free_text)
    topic = _forecast_topic_ar(_extract_forecast_value(raw, "المحور"))
    score_txt = _extract_forecast_value(raw, "المجموع الرقمي")
    classification = _extract_forecast_value(raw, "التصنيف")
    indication = _extract_forecast_value(raw, "نوع الدلالة")

    try:
        score_num = int(re.search(r"\d+", score_txt or "").group(0))
    except Exception:
        score_num = 0

    if score_num >= 85 or "قوية جدًا" in classification:
        strength_text = "الفترة قوية جدًا وتستحق الانتباه، لأن موضوعها حاضر بوضوح في حياتك وقد يدفعك إلى قرار أو تطور ملموس."
    elif score_num >= 70 or "قوية" in classification:
        strength_text = "الفترة قوية، وفيها قابلية واضحة لتحريك الموضوع، لكنها تحتاج خطوة واقعية وقرارًا هادئًا حتى تظهر نتيجتها."
    elif score_num >= 50 or "متوسطة" in classification:
        strength_text = "الفترة متوسطة؛ قد تفتح بابًا أو إشارة، لكنها لا تكفي وحدها لحسم القرار النهائي."
    else:
        strength_text = "الفترة خفيفة نسبيًا؛ تأثيرها أقرب إلى التفكير أو التهيئة النفسية من الحدث الحاسم."

    if "زواج" in topic or "خطوبة" in topic:
        focus = (
            "في موضوع الزواج والخطوبة، القراءة تشير إلى ارتفاع قابلية ظهور رغبة جدية في الاستقرار أو تحريك ملف ارتباط رسمي. "
            "الأثر العملي ليس مجرد انجذاب عابر، بل ميل إلى تقييم العلاقة من ناحية الواقع، القبول، النضج، والقدرة على تحويل المشاعر إلى خطوة معلنة."
        )
        advice = (
            "التصرف الأفضل: لا تتعامل مع الفترة كوعود قطعية، بل كنافذة تساعد على ترتيب القرار. "
            "إن كانت هناك علاقة قائمة فالأفضل فتح حوار هادئ حول النية والوضوح. وإن لم تكن هناك علاقة، فالفترة تصلح لزيادة القابلية للتعارف الجاد بشرط عدم التسرع في الحكم."
        )
    elif "عاطف" in topic or "عودة" in topic:
        focus = "عاطفيًا، الفترة ترفع الحساسية والرغبة في الفهم أو التواصل، وقد تجعل المشاعر أو الذكريات أكثر حضورًا من المعتاد."
        advice = "التصرف الأفضل: أعطِ المشاعر وقتها، لكن لا تبنِ قرارًا كبيرًا على لحظة اندفاع أو حنين مؤقت."
    elif "عمل" in topic or "مهنة" in topic:
        focus = "مهنيًا، الفترة تميل إلى تحريك موضوع المكانة أو المسؤولية أو فرصة الظهور، وقد تفتح بابًا للتفاوض أو ترتيب مسار جديد."
        advice = "التصرف الأفضل: جهّز أوراقك وخطتك، وادخل أي فرصة بروح منظمة لا برد فعل سريع."
    elif "مال" in topic:
        focus = "ماليًا، الفترة قد تزيد التفكير بالموارد والربح والالتزامات، وتحتاج إلى موازنة بين الرغبة في التوسع والحذر من المخاطرة."
        advice = "التصرف الأفضل: لا تدخل قرارًا ماليًا كبيرًا بلا مراجعة، واستفد من الفرص الصغيرة الواضحة قبل المخاطرات الواسعة."
    else:
        focus = "هذه الفترة ترفع حضور الموضوع المختار في حياتك، وتجعل القرار أو المراجعة أو التحرك العملي أكثر احتمالًا من الأيام العادية."
        advice = "التصرف الأفضل: راقب الإشارات الواقعية، وخذ خطوة محسوبة عندما يكون الباب واضحًا، وتجنب المبالغة أو الاستعجال."

    warning_bits = []
    if "مندفع" in raw or "متوتر" in raw or "المريخ" in raw:
        warning_bits.append("توجد قابلية للاندفاع أو التوتر، لذلك تجنّب القرار السريع وقت الانفعال.")
    if "تأخير" in raw or "زحل" in raw or "ثقيل" in raw:
        warning_bits.append("قد تظهر مسؤولية أو تأخير، وهذا لا يلغي الفرصة لكنه يطلب صبرًا وتنظيمًا.")
    if "تشوش" in raw or "نبتون" in raw:
        warning_bits.append("الغموض وارد، لذلك اطلب وضوحًا ولا تكتفِ بالانطباع أو الكلام العام.")
    if not warning_bits:
        warning_bits.append("أهم نقطة حذر هي عدم تحويل الترشيح الفلكي إلى استعجال؛ الواقع والاختيار الشخصي يبقيان عاملين حاسمين.")

    lines = []
    if base:
        lines.append(base)
        lines.append("")
    lines.extend([
        "التقرير الاحترافي العملي",
        "",
        f"الموضوع: {topic}",
        f"قوة الفترة: {classification or marriage_strength_label(score_num) if 'marriage_strength_label' in globals() else classification or 'غير محددة'}",
        "",
        "الخلاصة العملية:",
        strength_text,
        "",
        "كيف يؤثر ذلك عليك؟",
        focus,
        "",
        "أين تظهر الفرصة؟",
        "تظهر الفرصة عندما يتحول الشعور أو الرغبة إلى سلوك واضح: حوار، مبادرة محسوبة، قبول اجتماعي، أو ترتيب واقعي للخطوة التالية.",
        "",
        "أين يظهر الضغط؟",
        " ".join(warning_bits),
        "",
        "ما التصرف الأفضل الآن؟",
        advice,
        "",
        "الخلاصة النهائية:",
        "الفترة داعمة للتحريك وليست وعدًا قطعيًا. فائدتها الكبرى أنها تساعدك على معرفة متى تتحرك، ومتى تنتظر حتى تتضح الصورة أكثر.",
    ])
    return "\n".join(lines).strip()


