# كود المطور الماستر: يفتح كل التقارير الاحترافية ولا يُستهلك.
MASTER_ACCESS_CODE = os.environ.get("MASTER_ACCESS_CODE", "Abo_saj_2026+08@")
MASTER_ACCESS_CODE_NORMALIZED = None  # يضبط بعد تعريف normalize_premium_code


# سجل مستقل للأكواد المستخدمة.
# لا يتم لمس هذا الملف عند استخراج التقرير الأولي، بل فقط عند فتح التقرير الاحترافي بنجاح.
USED_PREMIUM_CODES_FILE = os.environ.get("USED_PREMIUM_CODES_FILE", "used_premium_codes_master.json")

def normalize_premium_code(code: str) -> str:
    """تطبيع كود الفتح حتى يقبل النسخ من الهاتف أو تيليغرام مع اختلاف أشكال الشرطة."""
    clean = (code or "").strip().upper()
    for ch in ["–", "—", "−", "‑", "‒", "﹘", "－", "_", " "]:
        clean = clean.replace(ch, "-" if ch != " " else "")
    while "--" in clean:
        clean = clean.replace("--", "-")
    return clean

def load_used_premium_codes() -> dict:
    try:
        if os.path.exists(USED_PREMIUM_CODES_FILE):
            with open(USED_PREMIUM_CODES_FILE, "r", encoding="utf-8") as f:
                data = json.load(f)
                return data if isinstance(data, dict) else {}
    except Exception:
        return {}
    return {}

def save_used_premium_codes(data: dict) -> None:
    try:
        with open(USED_PREMIUM_CODES_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

def premium_code_service(clean_code: str) -> str:
    if clean_code in RECTIFICATION_CODES:
        return "rectification"
    for service, codes in PREMIUM_CODES_BY_SERVICE.items():
        if clean_code in codes:
            return service
    return ""

def is_master_code(clean_code: str) -> bool:
    """كود المطور الماستر يفتح جميع الأقسام ولا يُستهلك.
    يعتمد فحصًا خاصًا بالماستر فقط: يحذف @ والفراغات والشرطة والشرطة السفلية
    حتى يعمل مع اتجاه الكتابة في حقول RTL إذا ظهر @ في البداية أو النهاية.
    لا يؤثر هذا على أكواد العملاء العادية.
    """
    try:
        def compact(value: str) -> str:
            v = str(value or "").strip().upper()
            # توحيد أشكال الشرطة قبل الحذف
            for ch in ["–", "—", "−", "‑", "‒", "﹘", "－"]:
                v = v.replace(ch, "-")
            # حذف رموز الاتجاه التي قد يضيفها الهاتف/المتصفح دون أن تظهر للمستخدم
            for ch in ["\u200e", "\u200f", "\u202a", "\u202b", "\u202c", "\u2066", "\u2067", "\u2068", "\u2069"]:
                v = v.replace(ch, "")
            # في كود الماستر فقط نتسامح مع مكان @ والشرطة والفراغ
            for ch in ["@", "-", "_", " ", "\t", "\n", "\r"]:
                v = v.replace(ch, "")
            return v

        master = compact(MASTER_ACCESS_CODE) or compact("Abo_saj_2026+08@")
        variants = {
            master,
            compact("Abo_saj_2026+08@"),
            compact("@Abo_saj_2026+08"),
            compact("Abo-saj-2026+08@"),
            compact("@Abo-saj-2026+08"),
        }
        return compact(clean_code) in variants
    except Exception:
        return False


def check_premium_code(code: str, service: str = "general") -> tuple[bool, str, str]:
    """يفحص الكود دون استهلاكه.
    service يحدد الأداة المطلوبة مثل: forecast / marriage / relationship / natal / midpoints / rectification.
    """
    clean = normalize_premium_code(code)
    if not clean:
        return False, clean, "يرجى إدخال كود فتح التقرير الاحترافي."

    if is_master_code(clean):
        return True, clean, "كود المطور الماستر صحيح."

    actual_service = premium_code_service(clean)
    if not actual_service:
        expected_prefix = PREMIUM_SERVICE_PREFIXES.get(service, "")
        if expected_prefix and not clean.startswith(expected_prefix + "-"):
            return False, clean, f"هذا الكود لا يطابق نوع هذه الخدمة. الكود المطلوب لهذه الصفحة يبدأ بـ {expected_prefix}-."
        return False, clean, "الكود غير صحيح أو غير موجود ضمن أكواد ASTROGATE."

    if service and service != "general" and actual_service != service:
        wanted = PREMIUM_SERVICE_LABELS.get(service, service)
        actual = PREMIUM_SERVICE_LABELS.get(actual_service, actual_service)
        wanted_prefix = PREMIUM_SERVICE_PREFIXES.get(service, "")
        return False, clean, f"هذا الكود مخصص لخدمة {actual}، ولا يفتح خدمة {wanted}. الكود الصحيح هنا يجب أن يبدأ بـ {wanted_prefix}-."

    used = load_used_premium_codes()
    if clean in used:
        return False, clean, "تم استخدام هذا الكود سابقًا. يرجى طلب كود جديد."
    return True, clean, "الكود صحيح."

def mark_premium_code_used(clean_code: str, service: str = "general") -> None:
    if is_master_code(clean_code):
        return
    used = load_used_premium_codes()
    actual_service = premium_code_service(clean_code) or service
    used[clean_code] = {
        "service": actual_service,
        "service_label": PREMIUM_SERVICE_LABELS.get(actual_service, actual_service),
        "used_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "status": "consumed_after_success"
    }
    save_used_premium_codes(used)

def consume_premium_code(code: str, service: str = "general") -> tuple[bool, str]:
    ok, clean, msg = check_premium_code(code, service)
    if not ok:
        return False, msg
    mark_premium_code_used(clean, service)
    return True, "تم فتح التقرير الاحترافي بنجاح."

