def aspect_sentence_for_planet(planet_ar: str, aspects) -> str:
    related = []
    for a, b, asp, orb in aspects:
        if a == planet_ar:
            related.append(f"{asp} {b}")
        elif b == planet_ar:
            related.append(f"{asp} {a}")
    if not related:
        return "لا تظهر له اتصالات رئيسية قوية ضمن الأورب المعتمد في هذه النسخة، لذلك تُقرأ دلالته أساسًا من البرج والبيت والحد."
    return "أبرز اتصالاته: " + "، ".join(related[:4]) + "."


def planet_reading_text(key: str, p: BodyPosition, aspects) -> str:
    planet_meaning = PLANET_MEANINGS.get(key, "")
    sign_trait = SIGN_SIMPLE_TRAITS.get(p.sign, "")
    house_theme = HOUSE_MEANINGS.get(p.house, "").replace(".", "")
    constitution = planet_constitution_analysis(key, p)
    reflection = constitution.get("reflection", "")
    retro = " كما أن تأثيره يميل إلى العمل داخليًا أولًا، فيحتاج إلى وقت ومراجعة قبل أن يظهر بصورة واضحة في السلوك." if p.retrograde else ""
    asp_text = aspect_sentence_for_planet(p.name_ar, aspects)
    asp_text = asp_text.replace("أبرز اتصالاته:", "أبرز ما يفعّله في داخلك:")
    asp_text = re.sub(r"\bاقتران\b|\bتسديس\b|\bتربيع\b|\bتثليث\b|\bمقابلة\b", "تأثير مع", asp_text)
    return (
        f"{p.name_ar}: يمثل {planet_meaning} "
        f"في حياتك يظهر أثره عبر {sign_trait} "
        f"ويرتبط خصوصًا بمجال {house_theme}. "
        f"الأثر العملي: هذه الطاقة تشرح كيف تتصرف عندما تبحث عن {planet_meaning} "
        f"وكيف يمكن أن تتحول إلى قوة إذا استُخدمت بوعي بدل أن تعمل كرد فعل تلقائي. "
        f"{reflection} {retro} {asp_text}"
    )

def house_reading_text(house_num: int, cusp_lon: float, positions) -> str:
    sign, degree = sign_from_lon(cusp_lon)
    ruler = SIGN_RULERS.get(sign, "")
    planets_inside = [p.name_ar for p in positions.values() if p.house == house_num]
    if planets_inside:
        planets_text = "هذا المجال نشط في حياتك، لأن طاقاته تظهر من خلال: " + "، ".join(planets_inside) + "."
    else:
        planets_text = "هذا المجال يعمل بهدوء أكبر، لكنه يبقى مهمًا ويظهر من خلال اختياراتك وظروفك المتكررة."
    return (
        f"مجال {house_num}: يرتبط بـ {HOUSE_MEANINGS[house_num]} "
        f"تأثيره عليك يميل إلى نبرة {SIGN_SIMPLE_TRAITS.get(sign, '')} "
        f"ومفتاح التعامل معه هو طاقة {ruler}. {planets_text} "
        "الخلاصة العملية: راقب هذا المجال من حياتك؛ فهو يوضح أين تحتاج إلى تنظيم، أين تحتاج إلى مرونة، وأين يمكن أن تظهر فرصة نمو واضحة."
    )

