def generate_supporting_techniques(positions, cusps, angles, aspects, element_scores) -> List[str]:
    items: List[str] = []
    dominant_element = strongest_element(element_scores)
    element_text = {
        "نار": "أنت تتحرك أفضل عندما يوجد حماس وهدف واضح، لكنك تحتاج إلى تهدئة الاندفاع حتى لا تستنزف طاقتك بسرعة.",
        "تراب": "أنت تتحرك أفضل عندما ترى نتائج ملموسة وخطة واقعية، لكنك تحتاج إلى عدم تحويل الحذر إلى جمود.",
        "هواء": "أنت تتحرك أفضل عبر الفكرة والحوار والتعلم، لكنك تحتاج إلى تقليل التشتت وكثرة الاحتمالات.",
        "ماء": "أنت تتحرك أفضل عندما تكون مشاعرك آمنة وواضحة، لكنك تحتاج إلى عدم امتصاص ضغط الآخرين."
    }
    items.append(f"مزاج الطاقة العام: {element_text.get(dominant_element, '')}")
    modes = modality_scores(positions)
    dominant_mode = max(modes, key=lambda k: modes[k])
    mode_text = {
        "مبادر": "طريقة حركتك تميل إلى فتح الأبواب والبدء، والتحدي هو إكمال ما تبدأه.",
        "ثابت": "طريقة حركتك تميل إلى الصبر والثبات، والتحدي هو قبول التغيير عند الحاجة.",
        "متغير": "طريقة حركتك تميل إلى التكيّف والفهم السريع، والتحدي هو تثبيت القرار وعدم التشتت."
    }
    items.append(mode_text.get(dominant_mode, ""))
    angular_planets = [p.name_ar for p in positions.values() if p.house in [1, 4, 7, 10]]
    if angular_planets:
        items.append("هناك طاقات ظاهرة بقوة في حياتك، لذلك لا تبقى داخلية فقط؛ أبرزها: " + "، ".join(angular_planets[:8]) + ".")
    else:
        items.append("طاقتك تميل إلى العمل تدريجيًا وبهدوء، لذلك قد تظهر النتائج بعد تراكم داخلي لا بعد اندفاع مباشر.")
    hard = [x for x in aspects if x[2] in ["تربيع", "مقابلة"]]
    soft = [x for x in aspects if x[2] in ["تثليث", "تسديس"]]
    if hard:
        items.append("يوجد ضغط نفسي أو عملي واضح في بعض المحاور، لكنه قابل للتحول إلى نضج إذا تعاملت معه كدرس لا كعقوبة.")
    if soft:
        items.append("توجد منافذ دعم ومواهب كامنة، لكنها تحتاج إلى استخدام عملي حتى لا تبقى مجرد قابلية غير مستثمرة.")
    items.append("الخلاصة: التقرير لا يعرض الأرقام الفلكية للقارئ، بل يترجمها إلى أثر عملي يساعده على فهم نفسه واتخاذ قرار أوضح.")
    return items

def generate_dignity_summary(positions: Dict[str, BodyPosition]) -> List[str]:
    rows = []
    for key in ["Sun", "Moon", "Mercury", "Venus", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune", "Pluto"]:
        p = positions[key]
        info = planet_constitution_analysis(key, p)
        rows.append((int(info["score"]), p.name_ar, info["level"], key, info["reflection"]))
    rows.sort(key=lambda x: x[0], reverse=True)
    strongest = rows[:3]
    weakest = rows[-3:]
    items = []
    items.append(
        "أقوى مفاتيح الشخصية في هذه الخريطة: "
        + "، ".join([f"{name} ({level})" for score, name, level, key, reflection in strongest])
        + ". هذه المفاتيح تمثل مناطق يمكنك الاعتماد عليها عند القرار، الثقة، العمل، أو بناء العلاقات."
    )
    items.append(
        "أكثر المناطق التي تحتاج إلى وعي وتدريب: "
        + "، ".join([f"{name} ({level})" for score, name, level, key, reflection in weakest])
        + ". هذا لا يعني ضعفًا نهائيًا، بل يعني أن هذه الطاقات تحتاج إلى بيئة مناسبة وصبر حتى تتحول إلى قوة."
    )
    for score, name, level, key, reflection in rows:
        items.append(f"{name}: {level}. {reflection}")
    return items

