_RELATIONSHIP_ENGINE_CODE = '# -*- coding: utf-8 -*-\n"""\nASTROGATE - Relationship Compatibility V2\nتطبيق توافق العلاقات - نسخة مستقلة ثانية للاختبار\n\nالمميزات:\n- واجهة ويب Flask تعمل على http://127.0.0.1:5000\n- حساب خريطتين بواسطة Swiss Ephemeris ونظام Placidus\n- تحليل توافق مبسط ومفهوم للقارئ العادي\n- نسب: التوافق العام، الجذب، الاستقرار، التحديات، التواصل\n- تقرير أولي مجاني + تقرير احترافي بكود REL يعمل مرة واحدة\n\nالتثبيت في Pydroid/Railway:\npip install flask pyswisseph\n"""\n\nfrom __future__ import annotations\n\nfrom dataclasses import dataclass\nfrom datetime import datetime, timedelta\nfrom typing import Dict, List, Tuple, Optional\nimport math\nimport html\nimport json\nimport os\nimport re\n\ntry:\n    import swisseph as swe\nexcept Exception as exc:\n    swe = None\n\ntry:\n    from flask import Flask, request, render_template_string\nexcept Exception:\n    Flask = None\n\nSIGNS = [\n    "الحمل", "الثور", "الجوزاء", "السرطان",\n    "الأسد", "العذراء", "الميزان", "العقرب",\n    "القوس", "الجدي", "الدلو", "الحوت"\n]\n\nELEMENTS = {\n    "الحمل": "نار", "الأسد": "نار", "القوس": "نار",\n    "الثور": "تراب", "العذراء": "تراب", "الجدي": "تراب",\n    "الجوزاء": "هواء", "الميزان": "هواء", "الدلو": "هواء",\n    "السرطان": "ماء", "العقرب": "ماء", "الحوت": "ماء",\n}\n\nMODES = {\n    "الحمل": "كاردينال", "السرطان": "كاردينال", "الميزان": "كاردينال", "الجدي": "كاردينال",\n    "الثور": "ثابت", "الأسد": "ثابت", "العقرب": "ثابت", "الدلو": "ثابت",\n    "الجوزاء": "متغير", "العذراء": "متغير", "القوس": "متغير", "الحوت": "متغير",\n}\n\nPLANET_CODES = {}\nif swe:\n    PLANET_CODES = {\n        "الشمس": swe.SUN,\n        "القمر": swe.MOON,\n        "عطارد": swe.MERCURY,\n        "الزهرة": swe.VENUS,\n        "المريخ": swe.MARS,\n        "المشتري": swe.JUPITER,\n        "زحل": swe.SATURN,\n        "أورانوس": swe.URANUS,\n        "نبتون": swe.NEPTUNE,\n        "بلوتو": swe.PLUTO,\n    }\n\nSIGN_RULERS = {\n    "الحمل": "المريخ", "الثور": "الزهرة", "الجوزاء": "عطارد", "السرطان": "القمر",\n    "الأسد": "الشمس", "العذراء": "عطارد", "الميزان": "الزهرة", "العقرب": "المريخ",\n    "القوس": "المشتري", "الجدي": "زحل", "الدلو": "زحل", "الحوت": "المشتري",\n}\n\nASPECTS = [\n    ("اقتران", 0, 8),\n    ("تسديس", 60, 5),\n    ("تربيع", 90, 6),\n    ("تثليث", 120, 6),\n    ("مقابلة", 180, 8),\n]\n\nCITY_OPTIONS = [\n    ("33.3152,44.3661,3", "العراق - بغداد"),\n    ("31.9860,44.5980,3", "العراق - الشامية"),\n    ("31.9840,44.9250,3", "العراق - الديوانية"),\n    ("32.6160,44.0249,3", "العراق - كربلاء"),\n    ("32.0000,44.3333,3", "العراق - النجف"),\n    ("30.5085,47.7804,3", "العراق - البصرة"),\n    ("36.1901,44.0092,3", "العراق - أربيل"),\n    ("35.5611,45.4356,3", "العراق - السليمانية"),\n    ("36.3489,43.1577,3", "العراق - الموصل"),\n    ("30.0444,31.2357,2", "مصر - القاهرة"),\n    ("24.7136,46.6753,3", "السعودية - الرياض"),\n    ("25.2048,55.2708,4", "الإمارات - دبي"),\n    ("35.6892,51.3890,3.5", "إيران - طهران"),\n    ("41.0082,28.9784,3", "تركيا - إسطنبول"),\n]\n\n\ndef norm(x: float) -> float:\n    return x % 360.0\n\n\ndef sign_name(deg: float) -> str:\n    return SIGNS[int(norm(deg) // 30)]\n\n\ndef degree_in_sign(deg: float) -> Tuple[int, int]:\n    d = norm(deg) % 30\n    whole = int(d)\n    minute = int(round((d - whole) * 60))\n    if minute == 60:\n        whole += 1\n        minute = 0\n    if whole == 30:\n        whole = 0\n    return whole, minute\n\n\ndef fmt_pos(deg: float) -> str:\n    d, m = degree_in_sign(deg)\n    return f"{d}°{m:02d}′ {sign_name(deg)}"\n\n\ndef distance(a: float, b: float) -> float:\n    diff = abs(norm(a) - norm(b))\n    return min(diff, 360 - diff)\n\n\ndef aspect_between(a: float, b: float) -> Optional[Tuple[str, float]]:\n    diff = distance(a, b)\n    best = None\n    for name, angle, orb in ASPECTS:\n        off = abs(diff - angle)\n        if off <= orb:\n            if best is None or off < best[1]:\n                best = (name, round(off, 2))\n    return best\n\n\ndef in_arc(x: float, start: float, end: float) -> bool:\n    x, start, end = norm(x), norm(start), norm(end)\n    if start <= end:\n        return start <= x < end\n    return x >= start or x < end\n\n\ndef house_of(deg: float, cusps: List[float]) -> int:\n    for i in range(12):\n        if in_arc(deg, cusps[i], cusps[(i + 1) % 12]):\n            return i + 1\n    return 1\n\n\ndef house_ruler(cusps: List[float], house_num: int) -> Tuple[str, str]:\n    sign = sign_name(cusps[house_num - 1])\n    return sign, SIGN_RULERS.get(sign, "")\n\n\n@dataclass\nclass BirthData:\n    name: str\n    gender: str\n    year: int\n    month: int\n    day: int\n    hour: int\n    minute: int\n    timezone: float\n    latitude: float\n    longitude: float\n\n\n@dataclass\nclass Chart:\n    data: BirthData\n    jd: float\n    planets: Dict[str, Dict]\n    cusps: List[float]\n    asc: float\n    mc: float\n\n\ndef calculate_chart(data: BirthData) -> Chart:\n    if swe is None:\n        raise RuntimeError("مكتبة pyswisseph غير مثبتة. ثبّتها بالأمر: pip install pyswisseph")\n\n    local_dt = datetime(data.year, data.month, data.day, data.hour, data.minute)\n    utc_dt = local_dt - timedelta(hours=data.timezone)\n    ut = utc_dt.hour + utc_dt.minute / 60 + utc_dt.second / 3600\n    jd = swe.julday(utc_dt.year, utc_dt.month, utc_dt.day, ut)\n\n    houses = swe.houses(jd, data.latitude, data.longitude, b"P")\n    cusps = [norm(x) for x in houses[0]]\n    asc = norm(houses[1][0])\n    mc = norm(houses[1][1])\n\n    planets = {}\n    for name, code in PLANET_CODES.items():\n        calc = swe.calc_ut(jd, code, swe.FLG_SPEED)[0]\n        lon = norm(calc[0])\n        planets[name] = {\n            "lon": lon,\n            "pos": fmt_pos(lon),\n            "sign": sign_name(lon),\n            "house": house_of(lon, cusps),\n            "speed": calc[3],\n            "retro": calc[3] < 0,\n        }\n    return Chart(data=data, jd=jd, planets=planets, cusps=cusps, asc=asc, mc=mc)\n\n\ndef aspect_score(planet_a: str, planet_b: str, aspect: str, orb: float) -> Tuple[int, str]:\n    """يرجع: نقاط، المجال المتأثر."""\n    pair = {planet_a, planet_b}\n    closeness = max(0, 1 - orb / 8)\n\n    score = 0\n    field = "عام"\n\n    easy = aspect in ["اقتران", "تسديس", "تثليث"]\n    hard = aspect in ["تربيع", "مقابلة"]\n\n    if pair == {"الشمس", "القمر"}:\n        field = "انسجام نفسي"\n        score = 18 if easy else -10\n    elif pair == {"القمر", "الزهرة"}:\n        field = "حنان وقبول"\n        score = 18 if easy else -8\n    elif pair == {"الزهرة", "المريخ"}:\n        field = "جذب عاطفي وجسدي"\n        score = 22 if easy or aspect == "مقابلة" else 8\n    elif pair == {"عطارد", "القمر"} or pair == {"عطارد", "الشمس"}:\n        field = "تواصل وفهم"\n        score = 14 if easy else -8\n    elif pair == {"عطارد", "عطارد"}:\n        field = "لغة الحوار"\n        score = 14 if easy else -7\n    elif pair == {"الزهرة", "الزهرة"}:\n        field = "ذوق عاطفي مشترك"\n        score = 15 if easy else -6\n    elif pair == {"القمر", "القمر"}:\n        field = "راحة يومية"\n        score = 16 if easy else -8\n    elif "زحل" in pair and ("الزهرة" in pair or "القمر" in pair or "الشمس" in pair):\n        field = "اختبار وثبات"\n        score = 10 if easy else -18\n    elif "المشتري" in pair and ("الشمس" in pair or "القمر" in pair or "الزهرة" in pair):\n        field = "تفاؤل ودعم"\n        score = 16 if easy else 5\n    elif "المريخ" in pair and ("القمر" in pair or "عطارد" in pair):\n        field = "توتر وانفعال"\n        score = 5 if easy else -14\n    else:\n        if easy:\n            score = 5\n        elif hard:\n            score = -4\n\n    return int(score * (0.55 + 0.45 * closeness)), field\n\n\ndef element_score(sign1: str, sign2: str) -> int:\n    e1, e2 = ELEMENTS[sign1], ELEMENTS[sign2]\n    if e1 == e2:\n        return 12\n    if {e1, e2} in [{"نار", "هواء"}, {"تراب", "ماء"}]:\n        return 8\n    if {e1, e2} in [{"نار", "ماء"}, {"هواء", "تراب"}]:\n        return -6\n    return 0\n\n\ndef score_to_label(score: int) -> str:\n    if score < 35:\n        return "صعب ويحتاج وعيًا كبيرًا"\n    if score < 50:\n        return "متوسط مع تحديات واضحة"\n    if score < 70:\n        return "جيد وقابل للنمو"\n    if score < 85:\n        return "قوي ومشجع"\n    return "قوي جدًا"\n\n\ndef clamp(x: int, low: int = 0, high: int = 100) -> int:\n    return max(low, min(high, int(x)))\n\n\ndef analyze_relationship(c1: Chart, c2: Chart) -> Dict:\n    p1, p2 = c1.planets, c2.planets\n\n    aspect_hits = []\n    totals = {"جذب": 45, "استقرار": 45, "تواصل": 45, "انسجام نفسي": 45, "تحديات": 35}\n    supports = []\n    warnings = []\n\n    important_pairs = [\n        ("الشمس", "القمر"), ("القمر", "الشمس"),\n        ("القمر", "الزهرة"), ("الزهرة", "القمر"),\n        ("الزهرة", "المريخ"), ("المريخ", "الزهرة"),\n        ("عطارد", "الشمس"), ("الشمس", "عطارد"),\n        ("عطارد", "القمر"), ("القمر", "عطارد"),\n        ("عطارد", "عطارد"),\n        ("القمر", "القمر"), ("الزهرة", "الزهرة"),\n        ("زحل", "الزهرة"), ("الزهرة", "زحل"),\n        ("زحل", "القمر"), ("القمر", "زحل"),\n        ("زحل", "الشمس"), ("الشمس", "زحل"),\n        ("المشتري", "الشمس"), ("الشمس", "المشتري"),\n        ("المشتري", "القمر"), ("القمر", "المشتري"),\n        ("المشتري", "الزهرة"), ("الزهرة", "المشتري"),\n        ("المريخ", "القمر"), ("القمر", "المريخ"),\n        ("المريخ", "عطارد"), ("عطارد", "المريخ"),\n    ]\n\n    seen = set()\n    for a, b in important_pairs:\n        key = (a, b)\n        if key in seen:\n            continue\n        seen.add(key)\n        if a not in p1 or b not in p2:\n            continue\n        asp = aspect_between(p1[a]["lon"], p2[b]["lon"])\n        if not asp:\n            continue\n        asp_name, orb = asp\n        score, field = aspect_score(a, b, asp_name, orb)\n        aspect_hits.append({"from": a, "to": b, "aspect": asp_name, "orb": orb, "score": score, "field": field})\n\n        if field == "جذب عاطفي وجسدي":\n            totals["جذب"] += score\n        elif field in ["اختبار وثبات"]:\n            if score >= 0:\n                totals["استقرار"] += score\n            else:\n                totals["تحديات"] += abs(score)\n                totals["استقرار"] += int(score / 2)\n        elif field in ["تواصل وفهم", "لغة الحوار"]:\n            totals["تواصل"] += score\n        elif field in ["انسجام نفسي", "راحة يومية", "حنان وقبول"]:\n            totals["انسجام نفسي"] += score\n        elif field == "تفاؤل ودعم":\n            totals["استقرار"] += int(score * 0.6)\n            totals["انسجام نفسي"] += int(score * 0.4)\n        elif score < 0:\n            totals["تحديات"] += abs(score)\n        else:\n            totals["جذب"] += int(score / 2)\n\n    # توافق العناصر للشمس والقمر والزهرة\n    for a, b, label in [("الشمس", "الشمس", "الشمس"), ("القمر", "القمر", "القمر"), ("الزهرة", "الزهرة", "الزهرة")]:\n        es = element_score(p1[a]["sign"], p2[b]["sign"])\n        totals["انسجام نفسي"] += es if a != "الزهرة" else int(es * 0.5)\n        if a == "الزهرة":\n            totals["جذب"] += es\n        if es >= 8:\n            supports.append(f"توافق عنصر {label} يعطي قابلية للفهم الطبيعي بين الطرفين.")\n        elif es < 0:\n            warnings.append(f"اختلاف عنصر {label} قد يسبب اختلافًا في أسلوب التعبير والاحتياج.")\n\n    # السابع والخامس: هل كواكب طرف تقع في بيوت علاقة الطرف الآخر؟\n    for planet in ["الشمس", "القمر", "الزهرة", "المريخ", "المشتري"]:\n        h_in_1 = house_of(p2[planet]["lon"], c1.cusps)\n        h_in_2 = house_of(p1[planet]["lon"], c2.cusps)\n        if h_in_1 in [5, 7] or h_in_2 in [5, 7]:\n            totals["جذب"] += 5\n            supports.append(f"وجود {planet} لأحد الطرفين في بيت الحب أو الشراكة عند الآخر يقوّي الحضور العاطفي.")\n        if h_in_1 == 4 or h_in_2 == 4:\n            totals["استقرار"] += 4\n            supports.append(f"تفعيل البيت الرابع بواسطة {planet} يعطي إحساسًا بالبيت أو الألفة.")\n\n    aspect_hits.sort(key=lambda x: abs(x["score"]), reverse=True)\n\n    for h in aspect_hits[:8]:\n        line = f"{h[\'from\']} الطرف الأول {h[\'aspect\']} {h[\'to\']} الطرف الثاني بفارق {h[\'orb\']}°"\n        if h["score"] >= 8:\n            supports.append(line)\n        elif h["score"] <= -8:\n            warnings.append(line)\n\n    attraction = clamp(totals["جذب"])\n    stability = clamp(totals["استقرار"])\n    communication = clamp(totals["تواصل"])\n    emotional = clamp(totals["انسجام نفسي"])\n    challenge_raw = clamp(totals["تحديات"])\n    challenge_balance = clamp(100 - challenge_raw)\n\n    overall = clamp(round(\n        attraction * 0.25 +\n        stability * 0.25 +\n        communication * 0.18 +\n        emotional * 0.22 +\n        challenge_balance * 0.10\n    ))\n\n    if challenge_raw >= 70:\n        summary = "العلاقة تحمل جذبًا أو حضورًا واضحًا، لكنها تحتاج نضجًا وصبرًا لأن التحديات عالية."\n    elif overall >= 75:\n        summary = "التوافق قوي ومشجع، مع قابلية جيدة للاستمرار إذا وُجد احترام ووضوح."\n    elif overall >= 55:\n        summary = "التوافق جيد لكنه ليس خاليًا من الاختلافات. نجاح العلاقة يعتمد على الحوار وتنظيم التوقعات."\n    elif overall >= 40:\n        summary = "التوافق متوسط، وقد تظهر العلاقة متعبة إذا لم يكن هناك وعي بطريقة التعامل."\n    else:\n        summary = "التوافق صعب نسبيًا، ويحتاج الطرفان إلى جهد كبير لتقليل سوء الفهم والضغط."\n\n    return {\n        "overall": overall,\n        "label": score_to_label(overall),\n        "attraction": attraction,\n        "stability": stability,\n        "communication": communication,\n        "emotional": emotional,\n        "challenge_raw": challenge_raw,\n        "challenge_balance": challenge_balance,\n        "summary": summary,\n        "supports": list(dict.fromkeys(supports))[:6],\n        "warnings": list(dict.fromkeys(warnings))[:5],\n        "aspects": aspect_hits[:16],\n    }\n\n\ndef build_free_report(c1: Chart, c2: Chart, analysis: Dict) -> str:\n    lines = []\n    lines.append("تقرير توافق العلاقات - النسخة الأولية")\n    lines.append("=" * 46)\n    lines.append(f"الطرف الأول: {c1.data.name}")\n    lines.append(f"الطرف الثاني: {c2.data.name}")\n    lines.append("")\n    lines.append("النتيجة العامة")\n    lines.append("-------------")\n    lines.append(f"نسبة التوافق العامة: {analysis[\'overall\']} من 100")\n    lines.append(f"التقييم: {analysis[\'label\']}")\n    lines.append("")\n    lines.append("المؤشرات الأساسية")\n    lines.append("----------------")\n    lines.append(f"قوة الجذب: {analysis[\'attraction\']} من 100")\n    lines.append(f"قوة الاستقرار: {analysis[\'stability\']} من 100")\n    lines.append(f"قوة التواصل: {analysis[\'communication\']} من 100")\n    lines.append(f"الانسجام النفسي والعاطفي: {analysis[\'emotional\']} من 100")\n    lines.append(f"مستوى التحديات: {analysis[\'challenge_raw\']} من 100")\n    lines.append("")\n    lines.append("الخلاصة")\n    lines.append("-------")\n    lines.append(analysis["summary"])\n    lines.append("")\n    lines.append("أبرز نقاط القوة")\n    lines.append("----------------")\n    if analysis["supports"]:\n        for s in analysis["supports"][:3]:\n            lines.append(f"- {s}")\n    else:\n        lines.append("- لا تظهر نقاط قوة كبيرة في النسخة الأولية، ويحتاج الأمر إلى تحليل أعمق.")\n    lines.append("")\n    lines.append("أبرز التحديات")\n    lines.append("--------------")\n    if analysis["warnings"]:\n        for w in analysis["warnings"][:2]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("- لا تظهر تحديات حادة في النسخة الأولية.")\n    lines.append("")\n    lines.append("ملاحظة")\n    lines.append("------")\n    lines.append("هذا تقرير أولي يوضح اتجاه العلاقة. التقرير الاحترافي يمكن أن يشرح أسباب النتيجة، نقاط الجذب، نقاط الخلاف، واحتمالات الاستمرار بصورة أعمق.")\n    return "\\n".join(lines)\n\n\ndef build_professional_teaser() -> str:\n    return """التقرير الاحترافي المقفل يشمل:\n- التحليل العاطفي التفصيلي.\n- ديناميكية الانجذاب بين الطرفين.\n- التوافق النفسي وأسلوب التواصل.\n- فرص الاستقرار والاستمرار.\n- نقاط القوة ونقاط التحدي.\n- خلاصة عملية للعلاقة.\n\nللفتح اطلب كود توافق العلاقات من نوع REL-XXXX-XXXX عبر تيليغرام."""\n\n\n\n# =========================================================\n# نظام أكواد REL للتقرير الاحترافي - يعمل مرة واحدة\n# =========================================================\n\nREL_PREMIUM_CODES = {\n    "REL-93FC-3D4J",\n    "REL-ZMP9-GFDC",\n    "REL-NDFX-TJHY",\n    "REL-TYAH-QSGB",\n    "REL-HRLP-CY7D",\n    "REL-L7V3-YVGD",\n    "REL-CWBS-HCUF",\n    "REL-SLE4-FRJC",\n    "REL-E6PF-8D6R",\n    "REL-A8BF-DLUY",\n    "REL-5WWG-49JU",\n    "REL-FS2S-APDD",\n    "REL-CEZC-AKL9",\n    "REL-HVVS-7GFG",\n    "REL-Q8PR-R4ZQ",\n    "REL-GGTN-MCPR",\n    "REL-SJ8V-F8TH",\n    "REL-SAPG-VMG9",\n    "REL-YURN-ANU2",\n    "REL-KG9S-9LW7",\n    "REL-9UQ4-HY86",\n    "REL-4XCK-JSWR",\n    "REL-93VL-97UV",\n    "REL-HLYP-PHPA",\n    "REL-MR2S-SPR5",\n    "REL-4H5T-GQQY",\n    "REL-SFR4-EZW9",\n    "REL-4NNP-FBPM",\n    "REL-5GTD-N5A4",\n    "REL-RF6T-LFLC",\n    "REL-J7SC-C8HA",\n    "REL-MJXV-7G38",\n    "REL-V5CV-ZMU6",\n    "REL-HKPK-WBWB",\n    "REL-XBAN-8XWG",\n    "REL-X74R-7XYU",\n    "REL-E4JU-BK9G",\n    "REL-Z4KF-2X9B",\n    "REL-H75X-ZTQ9",\n    "REL-DAAG-BQKZ",\n    "REL-HAYG-CHKN",\n    "REL-QRGQ-3ZQZ",\n    "REL-KL6Q-5H7L",\n    "REL-PRDK-P2HY",\n    "REL-L2QH-MGM5",\n    "REL-9BPJ-YZ8Y",\n    "REL-B4RP-RNBX",\n    "REL-A5JN-DY9A",\n    "REL-68UJ-BAPL",\n    "REL-KQZD-VNXW",\n}\nUSED_REL_CODES_FILE = "used_rel_premium_codes_v2.json"\n\n\ndef normalize_premium_code(code: str) -> str:\n    code = str(code or "").strip().upper()\n    code = code.replace("–", "-").replace("—", "-").replace("−", "-")\n    code = re.sub(r"\\s+", "", code)\n    return code\n\n\ndef load_used_rel_codes() -> set:\n    if not os.path.exists(USED_REL_CODES_FILE):\n        return set()\n    try:\n        with open(USED_REL_CODES_FILE, "r", encoding="utf-8") as f:\n            data = json.load(f)\n        if isinstance(data, list):\n            return set(data)\n    except Exception:\n        return set()\n    return set()\n\n\ndef save_used_rel_codes(codes: set) -> None:\n    with open(USED_REL_CODES_FILE, "w", encoding="utf-8") as f:\n        json.dump(sorted(codes), f, ensure_ascii=False, indent=2)\n\n\ndef verify_rel_code_once(code: str) -> Tuple[bool, str, str]:\n    code = normalize_premium_code(code)\n    if not code:\n        return False, code, "يرجى إدخال كود فتح التقرير الاحترافي."\n    if not code.startswith("REL-"):\n        return False, code, "هذا الكود غير مخصص لتقرير توافق العلاقات."\n    if code not in REL_PREMIUM_CODES:\n        return False, code, "الكود غير صحيح أو غير موجود ضمن أكواد توافق العلاقات."\n    used = load_used_rel_codes()\n    if code in used:\n        return False, code, "تم استخدام هذا الكود سابقًا، يرجى طلب كود جديد."\n    return True, code, "صالح"\n\n\ndef consume_rel_code(code: str) -> None:\n    code = normalize_premium_code(code)\n    used = load_used_rel_codes()\n    used.add(code)\n    save_used_rel_codes(used)\n\n\ndef strength_word(value: int) -> str:\n    if value >= 80:\n        return "قوي جدًا"\n    if value >= 65:\n        return "قوي"\n    if value >= 45:\n        return "متوسط"\n    return "ضعيف"\n\n\ndef simple_field_text(value: int, good: str, mid: str, low: str) -> str:\n    if value >= 70:\n        return good\n    if value >= 45:\n        return mid\n    return low\n\n\ndef build_professional_report(c1: Chart, c2: Chart, analysis: Dict) -> str:\n    lines = []\n    lines.append("تقرير توافق العلاقات الاحترافي")\n    lines.append("=" * 46)\n    lines.append(f"الطرف الأول: {c1.data.name}")\n    lines.append(f"الطرف الثاني: {c2.data.name}")\n    lines.append("")\n\n    lines.append("الخلاصة العامة")\n    lines.append("--------------")\n    lines.append(f"نسبة التوافق العامة: {analysis[\'overall\']} من 100")\n    lines.append(f"التقييم العام: {analysis[\'label\']}")\n    lines.append(analysis["summary"])\n    lines.append("")\n\n    lines.append("الجانب العاطفي")\n    lines.append("---------------")\n    lines.append(f"الانسجام النفسي والعاطفي: {analysis[\'emotional\']} من 100 / {strength_word(analysis[\'emotional\'])}")\n    lines.append(simple_field_text(\n        analysis[\'emotional\'],\n        "توجد قابلية جيدة للشعور بالأمان والقبول بين الطرفين، وهذا يساعد العلاقة على النمو بهدوء.",\n        "يوجد انسجام عاطفي مقبول، لكنه يحتاج إلى تعبير أوضح عن الاحتياجات والمشاعر.",\n        "الجانب العاطفي يحتاج إلى وعي أكبر، لأن كل طرف قد يفهم مشاعر الآخر بطريقة مختلفة."\n    ))\n    lines.append("")\n\n    lines.append("الانجذاب")\n    lines.append("---------")\n    lines.append(f"قوة الانجذاب: {analysis[\'attraction\']} من 100 / {strength_word(analysis[\'attraction\'])}")\n    lines.append(simple_field_text(\n        analysis[\'attraction\'],\n        "الانجذاب واضح وقادر على إبقاء الحضور بين الطرفين نشطًا.",\n        "الانجذاب موجود لكنه قد يتذبذب إذا غاب الحوار أو كثرت الضغوط.",\n        "الانجذاب يحتاج إلى دعم عاطفي وفكري حتى لا يبقى ضعيفًا أو مؤقتًا."\n    ))\n    lines.append("")\n\n    lines.append("التواصل والتفاهم")\n    lines.append("----------------")\n    lines.append(f"قوة التواصل: {analysis[\'communication\']} من 100 / {strength_word(analysis[\'communication\'])}")\n    lines.append(simple_field_text(\n        analysis[\'communication\'],\n        "أسلوب التفكير والحوار بين الطرفين قابل للتفاهم، وهذا يقلل سوء الفهم.",\n        "التواصل متوسط؛ يحتاج الطرفان إلى توضيح المقاصد وعدم بناء الأحكام بسرعة.",\n        "قد تظهر صعوبة في الفهم المتبادل، لذلك يحتاج الحوار إلى هدوء وصراحة أكبر."\n    ))\n    lines.append("")\n\n    lines.append("الاستقرار وفرص الاستمرار")\n    lines.append("--------------------------")\n    lines.append(f"قوة الاستقرار: {analysis[\'stability\']} من 100 / {strength_word(analysis[\'stability\'])}")\n    lines.append(simple_field_text(\n        analysis[\'stability\'],\n        "العلاقة تملك عناصر جيدة للاستمرار إذا وُجد التزام واحترام متبادل.",\n        "فرص الاستمرار موجودة، لكنها تعتمد على طريقة إدارة الخلافات اليومية.",\n        "الاستقرار يحتاج إلى جهد واضح، لأن العلاقة قد تتأثر بسرعة بالضغط أو سوء الفهم."\n    ))\n    lines.append("")\n\n    lines.append("نقاط القوة")\n    lines.append("----------")\n    if analysis["supports"]:\n        for spt in analysis["supports"][:5]:\n            lines.append(f"- {spt}")\n    else:\n        lines.append("- توجد بعض عناصر التوافق، لكنها ليست بارزة بقوة في القراءة الحالية.")\n    lines.append("")\n\n    lines.append("نقاط تحتاج إلى انتباه")\n    lines.append("---------------------")\n    if analysis["warnings"]:\n        for w in analysis["warnings"][:5]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("- لا تظهر ضغوط حادة، لكن يبقى الحوار والوضوح عاملين أساسيين لنجاح العلاقة.")\n    lines.append("")\n\n    lines.append("التقييم العملي للعلاقة")\n    lines.append("----------------------")\n    if analysis[\'overall\'] >= 80:\n        lines.append("العلاقة قوية جدًا من حيث القابلية العامة، وتستحق البناء عليها إذا كانت الظروف الواقعية مناسبة.")\n    elif analysis[\'overall\'] >= 65:\n        lines.append("العلاقة جيدة ومشجعة، لكن نجاحها يحتاج إلى نضج في التعامل مع الاختلافات.")\n    elif analysis[\'overall\'] >= 45:\n        lines.append("العلاقة متوسطة؛ يمكن أن تنجح إذا وُجد وعي وصبر، لكنها ليست سهلة تلقائيًا.")\n    else:\n        lines.append("العلاقة تحتاج جهدًا كبيرًا، وقد يشعر الطرفان بتعب إذا لم تكن هناك رغبة حقيقية في الفهم والتغيير.")\n    lines.append("")\n    lines.append("تنبيه: هذا التقرير قراءة فلكية رمزية تساعد على فهم ديناميكية العلاقة، ولا يحل محل القرار الشخصي أو الواقع العملي.")\n    return "\\n".join(lines)\n\n\nHTML = """\n<!doctype html>\n<html lang="ar" dir="rtl">\n<head>\n<meta charset="utf-8">\n<title>توافق العلاقات - ASTROGATE</title>\n<meta name="viewport" content="width=device-width, initial-scale=1">\n<style>\nbody{font-family:Tahoma,Arial,sans-serif;background:#f4f1ea;margin:0;color:#2b2118}\n.container{max-width:1050px;margin:auto;padding:14px}\n.header{background:linear-gradient(135deg,#3b2517,#7b583f);color:white;padding:22px;border-radius:18px;margin-bottom:16px;text-align:center}\n.header h1{margin:0;font-size:24px}.header p{line-height:1.8;color:#f5e9dc}\n.card{background:white;border-radius:16px;padding:16px;margin-bottom:16px;box-shadow:0 4px 16px rgba(0,0,0,.08)}\n.card h2{margin-top:0;color:#4a2f1d;border-bottom:1px solid #e6d8c8;padding-bottom:8px;font-size:20px}\n.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.grid2{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}\nlabel{display:block;font-weight:bold;margin-bottom:5px;font-size:14px}input,select{width:100%;box-sizing:border-box;border:1px solid #d8c8b8;border-radius:10px;padding:10px;font-size:15px;background:#fffdf8}\nbutton{background:#6f4e37;color:white;border:0;border-radius:12px;padding:13px 18px;font-weight:bold;font-size:16px;cursor:pointer}.secondary{background:#4b5563}.button-row{display:flex;gap:10px;flex-wrap:wrap;margin-top:14px}\n.report{white-space:pre-wrap;line-height:1.9;background:#ecfdf5;color:#064e3b;border:1px solid #a7f3d0;border-radius:14px;padding:16px;font-size:15px;overflow-x:auto}\n.locked{white-space:pre-wrap;line-height:1.9;background:#fff7ed;border:1px solid #fed7aa;color:#7c2d12;border-radius:14px;padding:16px;font-size:15px}\n.premium-report{white-space:pre-wrap;line-height:1.9;background:#f8fafc;border:1px solid #cbd5e1;color:#111827;border-radius:14px;padding:16px;font-size:15px;overflow-x:auto}\n.success{background:#ecfdf5;color:#065f46;border:1px solid #a7f3d0;padding:12px;border-radius:12px;margin-bottom:14px}.premium-box{background:#fff7ed;border:1px solid #fed7aa;border-radius:14px;padding:16px;line-height:1.8}.premium-box input{margin:10px 0}.loadingOverlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.62);z-index:9999;align-items:center;justify-content:center;padding:20px}.loadingCard{background:#fff;color:#2b2118;max-width:430px;width:100%;border-radius:18px;padding:22px;text-align:center;box-shadow:0 10px 30px rgba(0,0,0,.25)}.progressOuter{width:100%;height:24px;background:#eadfd1;border-radius:14px;overflow:hidden;margin:16px 0}.progressInner{width:0%;height:100%;background:#7b583f;transition:width .45s}\n.error{white-space:pre-wrap;line-height:1.8;background:#fef2f2;border:1px solid #fecaca;color:#7f1d1d;padding:14px;border-radius:12px;margin-bottom:16px}\n.small{font-size:13px;color:#6b5d51;line-height:1.7}\n@media(max-width:800px){.grid,.grid2{grid-template-columns:1fr}.container{padding:10px}}\n</style>\n<script>\nfunction fillCity(sel, prefix){\n if(!sel.value) return;\n const p=sel.value.split(\',\');\n document.querySelector(`[name=\'${prefix}_lat\']`).value=p[0];\n document.querySelector(`[name=\'${prefix}_lon\']`).value=p[1];\n document.querySelector(`[name=\'${prefix}_tz\']`).value=p[2];\n}\nfunction copyReport(){\n const el=document.getElementById(\'reportText\');\n if(!el) return;\n navigator.clipboard.writeText(el.innerText).then(()=>alert(\'تم نسخ التقرير\'));\n}\nfunction showLoading(message){\n const box=document.getElementById(\'loadingOverlay\');\n const bar=document.getElementById(\'progressBar\');\n const txt=document.getElementById(\'progressText\');\n if(!box||!bar||!txt) return;\n box.style.display=\'flex\';\n let steps=[[12,\'تجهيز بيانات الطرفين\'],[28,\'حساب الخرائط الفلكية\'],[45,\'فحص نقاط الانسجام\'],[63,\'تحليل الانجذاب والتواصل\'],[82,\'تقييم الاستقرار والتحديات\'],[96,message||\'إعداد التقرير\']];\n let i=0;\n bar.style.width=\'0%\'; txt.innerHTML=\'بدء التحليل...\';\n let timer=setInterval(()=>{ if(i<steps.length){bar.style.width=steps[i][0]+\'%\';txt.innerHTML=steps[i][1];i++;}else{clearInterval(timer);} },650);\n}\nfunction submitWithLoading(form, msg){showLoading(msg); setTimeout(()=>form.submit(),350); return false;}\n</script>\n</head>\n<body>\n<div class="loadingOverlay" id="loadingOverlay"><div class="loadingCard"><h3>جارٍ تحليل التوافق...</h3><div class="progressOuter"><div class="progressInner" id="progressBar"></div></div><p id="progressText">بدء التحليل...</p><p class="small">يتم الآن فحص عناصر العلاقة وتحويلها إلى تقرير واضح.</p></div></div>\n<div class="container">\n<div class="header"><h1>توافق العلاقات</h1><p>نسخة مستقلة أولى لاختبار تحليل التوافق بين شخصين.</p></div>\n{% if error %}<div class="error">{{ error }}</div>{% endif %}\n<form method="post" onsubmit="return submitWithLoading(this, \'إعداد التقرير الأولي\')">\n<div class="card"><h2>بيانات الطرف الأول</h2>\n<div class="grid"><div><label>الاسم</label><input name="a_name" value="{{ f.a_name }}"></div><div><label>الجنس</label><select name="a_gender"><option></option><option {% if f.a_gender==\'ذكر\' %}selected{% endif %}>ذكر</option><option {% if f.a_gender==\'أنثى\' %}selected{% endif %}>أنثى</option></select></div><div><label>فرق التوقيت</label><input name="a_tz" type="number" step="0.5" value="{{ f.a_tz }}"></div></div><br>\n<div class="grid"><div><label>السنة</label><input name="a_year" type="number" value="{{ f.a_year }}"></div><div><label>الشهر</label><input name="a_month" type="number" value="{{ f.a_month }}"></div><div><label>اليوم</label><input name="a_day" type="number" value="{{ f.a_day }}"></div></div><br>\n<div class="grid"><div><label>الساعة</label><input name="a_hour" type="number" value="{{ f.a_hour }}"></div><div><label>الدقيقة</label><input name="a_minute" type="number" value="{{ f.a_minute }}"></div><div><label>المدينة</label><select onchange="fillCity(this,\'a\')"><option value="">اختر المدينة</option>{% for v,l in cities %}<option value="{{v}}">{{l}}</option>{% endfor %}</select></div></div><br>\n<div class="grid2"><div><label>خط العرض</label><input name="a_lat" type="number" step="0.000001" value="{{ f.a_lat }}"></div><div><label>خط الطول</label><input name="a_lon" type="number" step="0.000001" value="{{ f.a_lon }}"></div></div>\n</div>\n<div class="card"><h2>بيانات الطرف الثاني</h2>\n<div class="grid"><div><label>الاسم</label><input name="b_name" value="{{ f.b_name }}"></div><div><label>الجنس</label><select name="b_gender"><option></option><option {% if f.b_gender==\'ذكر\' %}selected{% endif %}>ذكر</option><option {% if f.b_gender==\'أنثى\' %}selected{% endif %}>أنثى</option></select></div><div><label>فرق التوقيت</label><input name="b_tz" type="number" step="0.5" value="{{ f.b_tz }}"></div></div><br>\n<div class="grid"><div><label>السنة</label><input name="b_year" type="number" value="{{ f.b_year }}"></div><div><label>الشهر</label><input name="b_month" type="number" value="{{ f.b_month }}"></div><div><label>اليوم</label><input name="b_day" type="number" value="{{ f.b_day }}"></div></div><br>\n<div class="grid"><div><label>الساعة</label><input name="b_hour" type="number" value="{{ f.b_hour }}"></div><div><label>الدقيقة</label><input name="b_minute" type="number" value="{{ f.b_minute }}"></div><div><label>المدينة</label><select onchange="fillCity(this,\'b\')"><option value="">اختر المدينة</option>{% for v,l in cities %}<option value="{{v}}">{{l}}</option>{% endfor %}</select></div></div><br>\n<div class="grid2"><div><label>خط العرض</label><input name="b_lat" type="number" step="0.000001" value="{{ f.b_lat }}"></div><div><label>خط الطول</label><input name="b_lon" type="number" step="0.000001" value="{{ f.b_lon }}"></div></div>\n<div class="button-row"><button type="submit">استخراج تقرير التوافق</button><button class="secondary" type="button" onclick="location.href=\'/\'">مسح</button></div>\n</div>\n</form>\n{% if report %}<div class="card"><h2>التقرير الأولي المجاني</h2><button class="secondary" onclick="copyReport()">نسخ التقرير</button><br><br><div class="report" id="reportText">{{ report }}</div></div>{% endif %}\n{% if report %}<div class="card"><h2>التقرير الاحترافي المقفل</h2><div class="premium-box"><div class="locked">{{ locked }}</div><form method="post" onsubmit="return submitWithLoading(this, \'فتح التقرير الاحترافي\')"><input type="hidden" name="action" value="premium">{% for k,v in f.items() %}<input type="hidden" name="{{k}}" value="{{v}}">{% endfor %}<label>أدخل كود فتح تقرير التوافق</label><input name="premium_code" placeholder="أدخل كود الفتح هنا"><button type="submit">فتح التقرير الاحترافي</button></form><p class="small">الكود مخصص لتوافق العلاقات فقط ويعمل مرة واحدة.</p></div></div>{% endif %}\n{% if premium_report %}<div class="card" id="premiumResult"><h2>التقرير الاحترافي</h2><div class="success">تم فتح التقرير الاحترافي بنجاح.</div><button class="secondary" onclick="navigator.clipboard.writeText(document.getElementById(\'premiumText\').innerText).then(()=>alert(\'تم نسخ التقرير الاحترافي\'))">نسخ التقرير الاحترافي</button><br><br><div class="premium-report" id="premiumText">{{ premium_report }}</div></div><script>setTimeout(()=>{document.getElementById(\'premiumResult\')?.scrollIntoView({behavior:\'smooth\'});},300);</script>{% endif %}\n</div>\n</body>\n</html>\n"""\n\n\ndef default_form() -> Dict[str, str]:\n    keys = []\n    for p in ["a", "b"]:\n        keys += [f"{p}_name", f"{p}_gender", f"{p}_year", f"{p}_month", f"{p}_day", f"{p}_hour", f"{p}_minute", f"{p}_tz", f"{p}_lat", f"{p}_lon"]\n    f = {k: "" for k in keys}\n    f.update({"a_tz": "3", "b_tz": "3", "a_hour": "12", "a_minute": "0", "b_hour": "12", "b_minute": "0"})\n    return f\n\n\ndef read_form(req) -> Dict[str, str]:\n    f = default_form()\n    for k in f:\n        f[k] = str(req.get(k, f[k])).strip()\n    return f\n\n\ndef require(f: Dict[str, str], fields: List[Tuple[str, str]]):\n    missing = [label for key, label in fields if not f.get(key)]\n    if missing:\n        raise ValueError("يرجى ملء الحقول التالية:\\n- " + "\\n- ".join(missing))\n\n\ndef to_birth(prefix: str, f: Dict[str, str]) -> BirthData:\n    return BirthData(\n        name=f[f"{prefix}_name"] or ("الطرف الأول" if prefix == "a" else "الطرف الثاني"),\n        gender=f[f"{prefix}_gender"] or "غير محدد",\n        year=int(f[f"{prefix}_year"]),\n        month=int(f[f"{prefix}_month"]),\n        day=int(f[f"{prefix}_day"]),\n        hour=int(f[f"{prefix}_hour"]),\n        minute=int(f[f"{prefix}_minute"]),\n        timezone=float(f[f"{prefix}_tz"]),\n        latitude=float(f[f"{prefix}_lat"]),\n        longitude=float(f[f"{prefix}_lon"]),\n    )\n\n\ndef create_app():\n    if Flask is None:\n        raise RuntimeError("Flask غير مثبت. ثبته بالأمر: pip install flask")\n    app = Flask(__name__)\n\n    @app.route("/", methods=["GET", "POST"])\n    def index():\n        f = default_form()\n        report = ""\n        premium_report = ""\n        error = ""\n        locked = ""\n        if request.method == "POST":\n            try:\n                f = read_form(request.form)\n                required = []\n                for p, label in [("a", "الطرف الأول"), ("b", "الطرف الثاني")]:\n                    required += [\n                        (f"{p}_name", f"اسم {label}"), (f"{p}_gender", f"جنس {label}"),\n                        (f"{p}_year", f"سنة ميلاد {label}"), (f"{p}_month", f"شهر ميلاد {label}"), (f"{p}_day", f"يوم ميلاد {label}"),\n                        (f"{p}_hour", f"ساعة ميلاد {label}"), (f"{p}_minute", f"دقيقة ميلاد {label}"),\n                        (f"{p}_tz", f"فرق توقيت {label}"), (f"{p}_lat", f"خط عرض {label}"), (f"{p}_lon", f"خط طول {label}"),\n                    ]\n                require(f, required)\n                c1 = calculate_chart(to_birth("a", f))\n                c2 = calculate_chart(to_birth("b", f))\n                analysis = analyze_relationship(c1, c2)\n                report = build_free_report(c1, c2, analysis)\n                locked = build_professional_teaser()\n                if str(request.form.get(\'action\',\'\')).strip() == \'premium\':\n                    ok, normalized_code, msg = verify_rel_code_once(request.form.get(\'premium_code\',\'\'))\n                    if not ok:\n                        error = msg\n                    else:\n                        premium_report = build_professional_report(c1, c2, analysis)\n                        consume_rel_code(normalized_code)\n            except Exception as exc:\n                error = f"حدث خطأ أثناء الحساب:\\n{exc}"\n        return render_template_string(HTML, f=f, cities=CITY_OPTIONS, report=report, premium_report=premium_report, error=error, locked=locked)\n\n    return app\n\n\nif __name__ == "__main__":\n    app = create_app()\n    print("تشغيل تطبيق توافق العلاقات V2")\n    print("افتح الرابط: http://127.0.0.1:5000")\n    app.run(host="127.0.0.1", port=5000, debug=False)\n'
import types as _relationship_types
import sys as _relationship_sys
_RELATIONSHIP_MODULE_NAME = "_astrogate_relationship_engine"
_relationship_module = _relationship_types.ModuleType(_RELATIONSHIP_MODULE_NAME)
_relationship_module.__dict__["__name__"] = _RELATIONSHIP_MODULE_NAME
_relationship_module.__dict__["__file__"] = __file__
_REL_NS = _relationship_module.__dict__
_relationship_sys.modules[_RELATIONSHIP_MODULE_NAME] = _relationship_module
try:
    exec(_RELATIONSHIP_ENGINE_CODE, _REL_NS)
    RELATIONSHIP_ENGINE_READY = True
    RELATIONSHIP_ENGINE_ERROR = ""

except Exception as _rel_exc:
    RELATIONSHIP_ENGINE_READY = False
    RELATIONSHIP_ENGINE_ERROR = str(_rel_exc)


# ============================================================
# تحسين تقرير توافق العلاقات: مخاطر الانفصال + فرص الارتباط الرسمي
# ============================================================
def _rel_clamp_value(value, low=0, high=100):
    try:
        value = int(round(float(value)))
    except Exception:
        value = 0
    return max(low, min(high, value))


def _rel_level(value, reverse=False):
    value = _rel_clamp_value(value)
    if not reverse:
        if value >= 80:
            return "قوي جدًا"
        if value >= 65:
            return "قوي"
        if value >= 45:
            return "متوسط"
        return "ضعيف"
    else:
        if value >= 80:
            return "مرتفعة جدًا"
        if value >= 65:
            return "مرتفعة"
        if value >= 45:
            return "متوسطة"
        return "منخفضة"


def _rel_final_label(score):
    score = _rel_clamp_value(score)
    if score >= 85:
        return "ممتاز"
    if score >= 75:
        return "جيد جدًا"
    if score >= 60:
        return "جيد"
    if score >= 45:
        return "متوسط"
    return "يحتاج إلى جهد كبير"


def _rel_risk_text(risk):
    risk = _rel_clamp_value(risk)
    if risk >= 80:
        return "تظهر تحديات قوية قد تجعل العلاقة عرضة للقطيعة أو الانفصال إذا لم تُدار الخلافات بوعي واضح."
    if risk >= 65:
        return "توجد مؤشرات توتر مرتفعة نسبيًا، وقد تمر العلاقة بفترات شد وجذب أو ابتعاد إذا غاب الحوار."
    if risk >= 45:
        return "توجد تحديات متوسطة يمكن احتواؤها إذا كان الطرفان مستعدين للوضوح وتخفيف ردود الفعل."
    return "مخاطر الانفصال منخفضة نسبيًا، ولا تظهر مؤشرات ضغط حادة في القراءة الحالية."


def _rel_official_text(chance):
    chance = _rel_clamp_value(chance)
    if chance >= 80:
        return "فرص الارتباط الرسمي قوية جدًا إذا كانت الظروف الواقعية والاجتماعية مناسبة."
    if chance >= 65:
        return "فرص الارتباط الرسمي جيدة، لكنها تحتاج إلى خطوات واضحة وثبات في النية."
    if chance >= 45:
        return "فرص الارتباط الرسمي متوسطة، وقد تحتاج العلاقة إلى وقت أو نضج أكبر قبل القرار."
    return "فرص الارتباط الرسمي ضعيفة حاليًا، والعلاقة تحتاج إلى تثبيت أساسها أولًا."


def _rel_enhance_analysis(analysis):
    """يضيف مؤشرات واقعية للتوافق دون تغيير المحرك الأصلي بالكامل."""
    if not isinstance(analysis, dict):
        return analysis
    aspects = analysis.get("aspects", []) or []
    hard_hits = 0
    heavy_hits = 0
    emotional_pressure = 0
    for h in aspects:
        try:
            score = int(h.get("score", 0))
            a = str(h.get("from", ""))
            b = str(h.get("to", ""))
            pair = {a, b}
        except Exception:
            continue
        if score <= -8:
            hard_hits += 1
            if pair & {"زحل", "أورانوس", "نبتون", "بلوتو", "المريخ"}:
                heavy_hits += 1
            if pair & {"القمر", "الزهرة"}:
                emotional_pressure += 1

    attraction = _rel_clamp_value(analysis.get("attraction", 0))
    stability = _rel_clamp_value(analysis.get("stability", 0))
    communication = _rel_clamp_value(analysis.get("communication", 0))
    emotional = _rel_clamp_value(analysis.get("emotional", 0))
    challenge_raw = _rel_clamp_value(analysis.get("challenge_raw", 0))

    separation_risk = _rel_clamp_value(
        challenge_raw * 0.42
        + (100 - stability) * 0.26
        + (100 - communication) * 0.16
        + hard_hits * 4
        + heavy_hits * 5
        + emotional_pressure * 4
    )

    official_chance = _rel_clamp_value(
        stability * 0.34
        + emotional * 0.24
        + communication * 0.16
        + attraction * 0.14
        + (100 - separation_risk) * 0.12
    )

    adjusted_overall = _rel_clamp_value(
        attraction * 0.20
        + stability * 0.24
        + communication * 0.18
        + emotional * 0.20
        + official_chance * 0.10
        + (100 - separation_risk) * 0.08
    )

    # منع التناقض: لا تظهر نسبة توافق عالية جدًا مع مخاطر انفصال شديدة.
    if separation_risk >= 80:
        adjusted_overall = min(adjusted_overall, 58)
    elif separation_risk >= 65:
        adjusted_overall = min(adjusted_overall, 72)

    analysis["separation_risk"] = separation_risk
    analysis["official_chance"] = official_chance
    analysis["adjusted_overall"] = adjusted_overall
    analysis["final_label"] = _rel_final_label(adjusted_overall)

    if separation_risk >= 75:
        analysis["summary"] = (
            "العلاقة قد تحمل انجذابًا أو حضورًا واضحًا، لكن مؤشرات التوتر مرتفعة. "
            "الاستمرار ممكن فقط إذا وُجد وعي حقيقي بطريقة إدارة الخلافات والابتعاد عن ردود الفعل الحادة."
        )
    elif official_chance >= 70 and separation_risk < 55:
        analysis["summary"] = (
            "العلاقة واعدة وتملك عناصر جيدة للاستمرار والتطور إلى ارتباط رسمي، "
            "خصوصًا إذا استمر الحوار والوضوح بين الطرفين."
        )
    elif adjusted_overall >= 60:
        analysis["summary"] = (
            "العلاقة جيدة وقابلة للنمو، لكنها ليست خالية من الاختلافات. نجاحها يعتمد على النضج، الحوار، وتنظيم التوقعات."
        )
    elif adjusted_overall >= 45:
        analysis["summary"] = (
            "العلاقة متوسطة؛ قد تنجح إذا وُجد جهد متبادل، لكنها قد تصبح متعبة إذا تكررت نفس الخلافات دون معالجة."
        )
    else:
        analysis["summary"] = (
            "العلاقة تحتاج إلى جهد كبير، وقد تكون الضغوط أو اختلاف طريقة التعبير أعلى من عناصر الاستقرار في المرحلة الحالية."
        )
    return analysis


def _rel_build_free_report(c1, c2, analysis):
    analysis = _rel_enhance_analysis(analysis)
    overall = analysis.get("adjusted_overall", analysis.get("overall", 0))
    lines = []
    lines.append("تقرير توافق العلاقات - النسخة الأولية")
    lines.append("=" * 46)
    lines.append(f"الطرف الأول: {c1.data.name}")
    lines.append(f"الطرف الثاني: {c2.data.name}")
    lines.append("")
    lines.append("النتيجة العامة")
    lines.append("-------------")
    lines.append(f"التقييم العام: {overall} من 100")
    lines.append(f"الحكم المختصر: {analysis['final_label']}")
    lines.append("")
    lines.append("المؤشرات الرئيسية")
    lines.append("----------------")
    lines.append(f"الانسجام العاطفي: {_rel_level(analysis['emotional'])} ({analysis['emotional']} من 100)")
    lines.append(f"الانجذاب: {_rel_level(analysis['attraction'])} ({analysis['attraction']} من 100)")
    lines.append(f"التفاهم والتواصل: {_rel_level(analysis['communication'])} ({analysis['communication']} من 100)")
    lines.append(f"الاستقرار: {_rel_level(analysis['stability'])} ({analysis['stability']} من 100)")
    lines.append(f"مخاطر الانفصال: {_rel_level(analysis['separation_risk'], reverse=True)} ({analysis['separation_risk']} من 100)")
    lines.append(f"فرص الارتباط الرسمي: {_rel_level(analysis['official_chance'])} ({analysis['official_chance']} من 100)")
    lines.append("")
    lines.append("الخلاصة")
    lines.append("-------")
    lines.append(analysis["summary"])
    lines.append(_rel_risk_text(analysis["separation_risk"]))
    lines.append(_rel_official_text(analysis["official_chance"]))
    lines.append("")
    lines.append("أبرز نقطة قوة")
    lines.append("--------------")
    if analysis.get("supports"):
        lines.append(f"- {analysis['supports'][0]}")
    else:
        lines.append("- توجد قابلية للتقارب، لكن تحتاج إلى تحليل أعمق لتحديد أقوى مصدر دعم.")
    lines.append("")
    lines.append("أبرز نقطة تحتاج إلى انتباه")
    lines.append("-------------------------")
    if analysis.get("warnings"):
        lines.append(f"- {analysis['warnings'][0]}")
    else:
        lines.append("- لا تظهر تحديات حادة في التقرير الأولي، لكن يبقى الوضوح ضروريًا في أي علاقة.")
    lines.append("")
    lines.append("ملاحظة")
    lines.append("------")
    lines.append("هذا تقرير أولي. التقرير الاحترافي يشرح أسباب قوة العلاقة أو ضعفها، وهل التحديات مؤقتة أم عميقة، وما الذي يدعم الارتباط الرسمي أو يؤخره.")
    return "\n".join(lines)


def _rel_build_professional_report(c1, c2, analysis):
    analysis = _rel_enhance_analysis(analysis)
    overall = analysis.get("adjusted_overall", analysis.get("overall", 0))
    lines = []
    lines.append("تقرير توافق العلاقات الاحترافي")
    lines.append("=" * 46)
    lines.append(f"الطرف الأول: {c1.data.name}")
    lines.append(f"الطرف الثاني: {c2.data.name}")
    lines.append("")
    lines.append("الخلاصة العامة")
    lines.append("--------------")
    lines.append(f"التقييم العام المتوازن: {overall} من 100")
    lines.append(f"الحكم النهائي: {analysis['final_label']}")
    lines.append(analysis["summary"])
    lines.append("")
    lines.append("المؤشرات التفصيلية")
    lines.append("------------------")
    lines.append(f"الانسجام العاطفي: {analysis['emotional']} من 100 / {_rel_level(analysis['emotional'])}")
    lines.append(f"الانجذاب: {analysis['attraction']} من 100 / {_rel_level(analysis['attraction'])}")
    lines.append(f"التفاهم والتواصل: {analysis['communication']} من 100 / {_rel_level(analysis['communication'])}")
    lines.append(f"الاستقرار: {analysis['stability']} من 100 / {_rel_level(analysis['stability'])}")
    lines.append(f"مخاطر الانفصال: {analysis['separation_risk']} من 100 / {_rel_level(analysis['separation_risk'], reverse=True)}")
    lines.append(f"فرص الارتباط الرسمي: {analysis['official_chance']} من 100 / {_rel_level(analysis['official_chance'])}")
    lines.append("")
    lines.append("الجانب العاطفي")
    lines.append("---------------")
    if analysis['emotional'] >= 70:
        lines.append("توجد قابلية جيدة للشعور بالأمان والقبول بين الطرفين، وهذا يساعد العلاقة على النمو بهدوء.")
    elif analysis['emotional'] >= 45:
        lines.append("يوجد انسجام عاطفي مقبول، لكنه يحتاج إلى تعبير أوضح عن الاحتياجات والمشاعر.")
    else:
        lines.append("الجانب العاطفي يحتاج إلى وعي أكبر، لأن كل طرف قد يفهم مشاعر الآخر بطريقة مختلفة.")
    lines.append("")
    lines.append("الانجذاب")
    lines.append("---------")
    if analysis['attraction'] >= 70:
        lines.append("الانجذاب واضح وقادر على إبقاء الحضور بين الطرفين نشطًا.")
    elif analysis['attraction'] >= 45:
        lines.append("الانجذاب موجود لكنه قد يتذبذب إذا غاب الحوار أو كثرت الضغوط.")
    else:
        lines.append("الانجذاب يحتاج إلى دعم عاطفي وفكري حتى لا يبقى ضعيفًا أو مؤقتًا.")
    lines.append("")
    lines.append("التواصل والتفاهم")
    lines.append("----------------")
    if analysis['communication'] >= 70:
        lines.append("أسلوب التفكير والحوار بين الطرفين قابل للتفاهم، وهذا يقلل سوء الفهم.")
    elif analysis['communication'] >= 45:
        lines.append("التواصل متوسط؛ يحتاج الطرفان إلى توضيح المقاصد وعدم بناء الأحكام بسرعة.")
    else:
        lines.append("قد تظهر صعوبة في الفهم المتبادل، لذلك يحتاج الحوار إلى هدوء وصراحة أكبر.")
    lines.append("")
    lines.append("الاستقرار والاستمرار")
    lines.append("--------------------")
    if analysis['stability'] >= 70:
        lines.append("العلاقة تملك عناصر جيدة للاستمرار إذا وُجد التزام واحترام متبادل.")
    elif analysis['stability'] >= 45:
        lines.append("فرص الاستمرار موجودة، لكنها تعتمد على طريقة إدارة الخلافات اليومية.")
    else:
        lines.append("الاستقرار يحتاج إلى جهد واضح، لأن العلاقة قد تتأثر بسرعة بالضغط أو سوء الفهم.")
    lines.append("")
    lines.append("مخاطر الانفصال")
    lines.append("---------------")
    lines.append(_rel_risk_text(analysis['separation_risk']))
    lines.append("")
    lines.append("فرص الارتباط الرسمي")
    lines.append("--------------------")
    lines.append(_rel_official_text(analysis['official_chance']))
    lines.append("")
    lines.append("نقاط القوة")
    lines.append("----------")
    if analysis.get("supports"):
        for spt in analysis["supports"][:5]:
            lines.append(f"- {spt}")
    else:
        lines.append("- توجد بعض عناصر التوافق، لكنها ليست بارزة بقوة في القراءة الحالية.")
    lines.append("")
    lines.append("نقاط تحتاج إلى انتباه")
    lines.append("---------------------")
    if analysis.get("warnings"):
        for w in analysis["warnings"][:5]:
            lines.append(f"- {w}")
    else:
        lines.append("- لا تظهر ضغوط حادة، لكن يبقى الحوار والوضوح عاملين أساسيين لنجاح العلاقة.")
    lines.append("")
    lines.append("التقييم العملي للعلاقة")
    lines.append("----------------------")
    if analysis['separation_risk'] >= 75:
        lines.append("العلاقة تحتاج إلى وعي كبير؛ لا يكفي وجود الانجذاب إذا بقيت أسباب التوتر تتكرر دون معالجة.")
    elif overall >= 75 and analysis['official_chance'] >= 65:
        lines.append("العلاقة واعدة ويمكن البناء عليها، مع قابلية جيدة للاستمرار أو الارتباط إذا دعمتها الظروف الواقعية.")
    elif overall >= 60:
        lines.append("العلاقة جيدة وقابلة للنمو، لكنها تحتاج إلى إدارة ناضجة للاختلافات.")
    elif overall >= 45:
        lines.append("العلاقة متوسطة؛ يمكن أن تنجح إذا وُجد وعي وصبر، لكنها ليست سهلة تلقائيًا.")
    else:
        lines.append("العلاقة تحتاج جهدًا كبيرًا، وقد يشعر الطرفان بتعب إذا لم تكن هناك رغبة حقيقية في الفهم والتغيير.")
    lines.append("")
    lines.append("تنبيه: هذا التقرير قراءة فلكية رمزية تساعد على فهم ديناميكية العلاقة، ولا يحل محل القرار الشخصي أو الواقع العملي.")
    return "\n".join(lines)


if RELATIONSHIP_ENGINE_READY:
    _REL_NS["build_free_report"] = _rel_build_free_report
    _REL_NS["build_professional_report"] = _rel_build_professional_report


def relationship_profile_has_birth_data() -> bool:
    return profile_is_complete()


def build_relationship_chart_from_saved_profile():
    saved = session.get("astro_profile", {})
    if not isinstance(saved, dict) or not relationship_profile_has_birth_data():
        raise RuntimeError("يرجى إدخال بياناتك الفلكية أولًا من صفحة بياناتي الفلكية.")
    city_name = str(saved.get("city", "")).strip()
    country_code = str(saved.get("country_code", "")).strip()
    city_info = find_city(country_code, city_name)
    if not city_info:
        raise RuntimeError("لم أتمكن من تحديد مدينة الميلاد المحفوظة. يرجى إعادة حفظ بياناتك الفلكية.")
    birth = _REL_NS["BirthData"](
        name=str(saved.get("name", "الطرف الأول")) or "الطرف الأول",
        gender=str(saved.get("gender", "غير محدد")) or "غير محدد",
        year=int(saved.get("year")),
        month=int(saved.get("month")),
        day=int(saved.get("day")),
        hour=int(saved.get("hour")),
        minute=int(saved.get("minute")),
        timezone=float(saved.get("timezone_offset")),
        latitude=float(city_info["lat"]),
        longitude=float(city_info["lon"]),
    )
    return _REL_NS["calculate_chart"](birth), birth.name


def relationship_order_message(order_id: str, name: str, partner_name: str = "") -> str:
    return (
        "السلام عليكم، أرغب بطلب كود فتح التقرير الاحترافي لتوافق العلاقات في ASTROGATE.\n"
        f"رقم الطلب: {order_id}\n"
        f"الاسم: {name or 'غير مذكور'}\n"
        f"الطرف الثاني: {partner_name or 'غير مذكور'}\n"
        "أحتاج كود فتح للتقرير الاحترافي."
    )


