_RECTIFICATION_MODULE_CODE = '# -*- coding: utf-8 -*-\n"""\nBirth Rectification Web App for Pydroid\nمشروع تصحيح الميلاد - نسخة Pydroid Web V1.8\n\nالتشغيل:\n1) افتح Pydroid 3.\n2) ثبّت المكتبات:\n   pip install flask pyswisseph\n3) شغّل هذا الملف.\n4) افتح المتصفح على:\n   http://127.0.0.1:5000\n\nملاحظات:\n- الحسابات الفلكية تعتمد على Swiss Ephemeris عبر pyswisseph.\n- البيوت Placidus.\n- التصحيح يعتمد على محورين:\n  1) المحور الصحي.\n  2) محور الأحداث ذات التأثير العميق.\n- الملاحظات العامة تظهر بعد التصحيح ولا تدخل في الترجيح.\n"""\n\nfrom __future__ import annotations\n\nfrom datetime import datetime, timedelta\nfrom math import floor\nfrom typing import Dict, List, Tuple, Optional\nimport json\n\nfrom flask import request, render_template_string\n\ntry:\n    import swisseph as swe\nexcept Exception as e:\n    swe = None\n\n\n\n\nSIGNS_AR = [\n    "الحمل", "الثور", "الجوزاء", "السرطان",\n    "الأسد", "العذراء", "الميزان", "العقرب",\n    "القوس", "الجدي", "الدلو", "الحوت"\n]\n\nPLANET_IDS = {}\nif swe:\n    PLANET_IDS = {\n        "الشمس": swe.SUN,\n        "القمر": swe.MOON,\n        "عطارد": swe.MERCURY,\n        "الزهرة": swe.VENUS,\n        "المريخ": swe.MARS,\n        "المشتري": swe.JUPITER,\n        "زحل": swe.SATURN,\n        "أورانوس": swe.URANUS,\n        "نبتون": swe.NEPTUNE,\n        "بلوتو": swe.PLUTO,\n    }\n    if hasattr(swe, "CHIRON"):\n        PLANET_IDS["كيرون"] = swe.CHIRON\n    if hasattr(swe, "MEAN_NODE"):\n        PLANET_IDS["العقدة الشمالية"] = swe.MEAN_NODE\n\n\nTRADITIONAL_RULERS = {\n    0: "المريخ",\n    1: "الزهرة",\n    2: "عطارد",\n    3: "القمر",\n    4: "الشمس",\n    5: "عطارد",\n    6: "الزهرة",\n    7: "المريخ",\n    8: "المشتري",\n    9: "زحل",\n    10: "زحل",\n    11: "المشتري",\n}\n\nPTOLEMY_TERMS = {\n    0:  [(6, "المشتري"), (14, "الزهرة"), (21, "عطارد"), (26, "المريخ"), (30, "زحل")],\n    1:  [(8, "الزهرة"), (14, "عطارد"), (22, "المشتري"), (27, "زحل"), (30, "المريخ")],\n    2:  [(6, "عطارد"), (12, "المشتري"), (17, "الزهرة"), (24, "المريخ"), (30, "زحل")],\n    3:  [(7, "المريخ"), (13, "الزهرة"), (19, "عطارد"), (26, "المشتري"), (30, "زحل")],\n    4:  [(6, "زحل"), (13, "عطارد"), (19, "الزهرة"), (25, "المشتري"), (30, "المريخ")],\n    5:  [(7, "عطارد"), (13, "الزهرة"), (17, "المشتري"), (21, "المريخ"), (30, "زحل")],\n    6:  [(6, "زحل"), (14, "عطارد"), (21, "المشتري"), (28, "الزهرة"), (30, "المريخ")],\n    7:  [(7, "المريخ"), (11, "الزهرة"), (19, "عطارد"), (24, "المشتري"), (30, "زحل")],\n    8:  [(12, "المشتري"), (17, "الزهرة"), (21, "عطارد"), (26, "زحل"), (30, "المريخ")],\n    9:  [(7, "عطارد"), (14, "المشتري"), (22, "الزهرة"), (26, "زحل"), (30, "المريخ")],\n    10: [(7, "عطارد"), (13, "الزهرة"), (20, "المشتري"), (25, "المريخ"), (30, "زحل")],\n    11: [(12, "الزهرة"), (16, "المشتري"), (19, "عطارد"), (28, "المريخ"), (30, "زحل")],\n}\n\nASPECTS = {\n    "اقتران": (0, 6),\n    "تسديس": (60, 3),\n    "تربيع": (90, 5),\n    "تثليث": (120, 4),\n    "مقابلة": (180, 5),\n}\n\nHEALTH_PLANETS = ["زحل", "المريخ", "القمر", "كيرون", "نبتون", "بلوتو"]\nHEALTH_HOUSES = [1, 6, 8, 12]\n\nCITY_PRESETS = {\n    "العراق - بغداد": (33.3152, 44.3661, 3),\n    "العراق - النجف": (32.0000, 44.3333, 3),\n    "العراق - الديوانية": (31.9861, 44.9256, 3),\n    "العراق - الشامية": (31.9640, 44.6000, 3),\n    "العراق - كربلاء": (32.6160, 44.0249, 3),\n    "العراق - البصرة": (30.5085, 47.7804, 3),\n    "العراق - الموصل": (36.3450, 43.1570, 3),\n    "العراق - كركوك": (35.4681, 44.3922, 3),\n    "العراق - أربيل": (36.1911, 44.0092, 3),\n    "السعودية - الرياض": (24.7136, 46.6753, 3),\n    "السعودية - جدة": (21.4858, 39.1925, 3),\n    "السعودية - مكة": (21.3891, 39.8579, 3),\n    "السعودية - المدينة المنورة": (24.5247, 39.5692, 3),\n    "الكويت - مدينة الكويت": (29.3759, 47.9774, 3),\n    "الأردن - عمّان": (31.9539, 35.9106, 3),\n    "مصر - القاهرة": (30.0444, 31.2357, 2),\n    "مصر - الإسكندرية": (31.2001, 29.9187, 2),\n    "الإمارات - دبي": (25.2048, 55.2708, 4),\n    "الإمارات - أبوظبي": (24.4539, 54.3773, 4),\n    "قطر - الدوحة": (25.2854, 51.5310, 3),\n    "البحرين - المنامة": (26.2235, 50.5876, 3),\n    "عُمان - مسقط": (23.5880, 58.3829, 4),\n    "اليمن - صنعاء": (15.3694, 44.1910, 3),\n    "سوريا - دمشق": (33.5138, 36.2765, 3),\n    "لبنان - بيروت": (33.8938, 35.5018, 3),\n    "تركيا - إسطنبول": (41.0082, 28.9784, 3),\n    "إيران - طهران": (35.6892, 51.3890, 3.5),\n}\n\ndef rectification_city_payload() -> dict:\n    data = {}\n    for key, vals in CITY_PRESETS.items():\n        try:\n            country, city = key.split(" - ", 1)\n        except ValueError:\n            country, city = "", key\n        lat, lon, tz = vals\n        data.setdefault(country, []).append({"key": key, "city": city, "lat": lat, "lon": lon, "tz": tz})\n    for country in data:\n        data[country].sort(key=lambda x: x["city"])\n    return data\n\ndef rectification_country_options() -> list:\n    # يستخدم نفس قائمة الدول العالمية في المنصة الرئيسية، ولا يقتصر على الدول العربية.\n    try:\n        return build_country_list()\n    except Exception:\n        return [{"code": "IQ", "name": "Iraq / العراق"}]\n\ndef rectification_timezone_options() -> list:\n    return [\n        ("-12", "GMT -12"), ("-11", "GMT -11"), ("-10", "GMT -10"),\n        ("-9", "GMT -9"), ("-8", "GMT -8"), ("-7", "GMT -7"),\n        ("-6", "GMT -6"), ("-5", "GMT -5"), ("-4", "GMT -4"),\n        ("-3.5", "GMT -3:30"), ("-3", "GMT -3"), ("-2", "GMT -2"),\n        ("-1", "GMT -1"), ("0", "GMT 0"), ("1", "GMT +1"),\n        ("2", "GMT +2"), ("3", "GMT +3 - العراق / السعودية / الكويت / قطر / البحرين / اليمن"),\n        ("3.5", "GMT +3:30"), ("4", "GMT +4 - الإمارات / عُمان"),\n        ("4.5", "GMT +4:30"), ("5", "GMT +5"), ("5.5", "GMT +5:30"),\n        ("5.75", "GMT +5:45"), ("6", "GMT +6"), ("6.5", "GMT +6:30"),\n        ("7", "GMT +7"), ("8", "GMT +8"), ("8.75", "GMT +8:45"),\n        ("9", "GMT +9"), ("9.5", "GMT +9:30"), ("10", "GMT +10"),\n        ("10.5", "GMT +10:30"), ("11", "GMT +11"), ("12", "GMT +12"),\n        ("12.75", "GMT +12:45"), ("13", "GMT +13"), ("14", "GMT +14"),\n    ]\n\n\nHEALTH_OPTIONS = [\n    "مرض وراثي",\n    "عاهة خلقية",\n    "تشوه خلقي",\n    "إعاقة جسدية منذ الولادة",\n    "مشكلة في النمو",\n    "ضعف في أحد الأطراف",\n    "مشكلة في النظر منذ الولادة",\n    "مشكلة في السمع منذ الولادة",\n    "مشكلة في النطق أو الكلام",\n    "مشكلة عصبية منذ الولادة",\n    "السكري",\n    "ضغط الدم",\n    "أمراض القلب",\n    "أمراض الكلى",\n    "أمراض الكبد",\n    "أمراض الغدة الدرقية",\n    "أمراض الدم",\n    "أمراض المناعة",\n    "أمراض العظام والمفاصل",\n    "أمراض الجهاز التنفسي",\n    "أمراض الجهاز الهضمي",\n    "أمراض الجلد المزمنة",\n    "الصرع",\n    "التشنجات",\n    "الشقيقة أو الصداع المزمن",\n    "اضطرابات الأعصاب",\n    "القلق المزمن",\n    "الاكتئاب",\n    "اضطراب النوم",\n    "نوبات الهلع",\n    "عملية جراحية كبرى",\n    "عملية جراحية صغرى",\n    "حادث سير",\n    "كسر عظم",\n    "حرق",\n    "نزف أو جرح عميق",\n    "دخول مستشفى",\n    "رقود طويل",\n    "تخدير عام",\n    "إصابة تركت أثرًا دائمًا",\n    "مشكلة في العين",\n    "مشكلة في الأذن",\n    "مشكلة في الأسنان أو الفك",\n    "مشكلة في المعدة أو القولون",\n    "مشكلة في الجهاز التناسلي",\n    "مشكلة في الهرمونات",\n    "مشكلة في العمود الفقري",\n]\n\nEVENT_OPTIONS = [\n    "زواج",\n    "خطوبة",\n    "طلاق",\n    "انفصال عاطفي مهم",\n    "بداية علاقة مصيرية",\n    "نهاية علاقة مصيرية",\n    "ولادة أول طفل",\n    "ولادة طفل آخر",\n    "وفاة الأب",\n    "وفاة الأم",\n    "وفاة الزوج أو الزوجة",\n    "وفاة شخص مؤثر",\n    "مشكلة عائلية كبرى",\n    "تعيين",\n    "بداية عمل",\n    "ترقية",\n    "منصب مهم",\n    "فقدان عمل",\n    "تغيير مهنة",\n    "تقاعد",\n    "افتتاح مشروع",\n    "فشل مشروع",\n    "شهرة أو ظهور اجتماعي",\n    "انتقال من بيت",\n    "شراء بيت",\n    "بيع بيت",\n    "شراء سيارة",\n    "حادث سيارة",\n    "سفر مهم",\n    "هجرة",\n    "عودة من سفر",\n    "انتقال مدينة",\n    "انتقال دولة",\n    "ربح مالي كبير",\n    "خسارة مالية كبيرة",\n    "دين كبير",\n    "إرث",\n    "شراكة مالية",\n    "قضية قانونية",\n    "سجن أو توقيف",\n    "نزاع أو خصومة كبيرة",\n    "دخول الجامعة",\n    "تخرج",\n    "قبول دراسي",\n    "فشل أو انقطاع دراسة",\n    "شهادة مهمة",\n    "سفر للدراسة",\n]\n\nPRECISION_OPTIONS = [\n    ("birth", "منذ الولادة"),\n    ("day", "يوم دقيق"),\n    ("month", "شهر فقط"),\n    ("year", "سنة فقط"),\n]\n\nSEVERITY_OPTIONS = [1, 2, 3, 4, 5]\n\n\ndef norm360(x: float) -> float:\n    return x % 360.0\n\n\ndef shortest_arc(a: float, b: float) -> float:\n    d = abs(norm360(a) - norm360(b)) % 360.0\n    return min(d, 360.0 - d)\n\n\ndef sign_index(deg: float) -> int:\n    return int(norm360(deg) // 30)\n\n\ndef degree_in_sign(deg: float) -> float:\n    return norm360(deg) % 30.0\n\n\ndef format_degree(deg: float) -> str:\n    deg = norm360(deg)\n    s = sign_index(deg)\n    d = int(deg % 30)\n    m = int(round(((deg % 30) - d) * 60))\n    if m == 60:\n        d += 1\n        m = 0\n    return f"{d:02d}°{m:02d}′ {SIGNS_AR[s]}"\n\n\ndef ptolemy_term(deg: float) -> str:\n    s = sign_index(deg)\n    dins = degree_in_sign(deg)\n    for upper, ruler in PTOLEMY_TERMS[s]:\n        if dins < upper:\n            return ruler\n    return PTOLEMY_TERMS[s][-1][1]\n\n\ndef sign_ruler(deg: float) -> str:\n    return TRADITIONAL_RULERS[sign_index(deg)]\n\n\ndef aspect_score(\n    a: float,\n    b: float,\n    base_weight: float = 1.0,\n    hard_only: bool = False,\n    max_orb_override: Optional[float] = None\n) -> Tuple[float, Optional[str], float]:\n    dist = shortest_arc(a, b)\n    best = 0.0\n    best_name = None\n    best_delta = 999.0\n\n    for name, (angle, orb) in ASPECTS.items():\n        if hard_only and name not in ["اقتران", "تربيع", "مقابلة"]:\n            continue\n\n        used_orb = max_orb_override if max_orb_override is not None else orb\n        delta = abs(dist - angle)\n\n        if delta <= used_orb:\n            strength = (used_orb - delta) / used_orb\n            weight = base_weight\n            if name in ["اقتران", "تربيع", "مقابلة"]:\n                weight *= 1.20\n            score = max(0.0, strength * weight)\n            if score > best:\n                best = score\n                best_name = name\n                best_delta = delta\n\n    return best, best_name, best_delta\n\n\ndef parse_date_value(value: str) -> Optional[datetime]:\n    value = str(value or "").strip()\n    if not value or value.lower() in ["birth", "ولادة", "منذ الولادة"]:\n        return None\n\n    formats = ["%Y-%m-%d", "%Y/%m/%d", "%d-%m-%Y", "%d/%m/%Y", "%Y-%m", "%Y/%m", "%Y"]\n    for fmt in formats:\n        try:\n            return datetime.strptime(value, fmt)\n        except Exception:\n            continue\n\n    return None\n\n\ndef parse_event_lines(text: str, default_kind: str) -> List[dict]:\n    items = []\n    for raw in str(text or "").splitlines():\n        line = raw.strip()\n        if not line:\n            continue\n\n        parts = [p.strip() for p in line.split("|")]\n        while len(parts) < 5:\n            parts.append("")\n\n        item_type, date_s, precision, severity, notes = parts[:5]\n\n        try:\n            severity_int = int(float(severity)) if severity else 3\n            severity_int = max(1, min(5, severity_int))\n        except Exception:\n            severity_int = 3\n\n        items.append({\n            "kind": default_kind,\n            "type": item_type or ("حالة صحية" if default_kind == "health" else "حدث"),\n            "date_text": date_s,\n            "date": parse_date_value(date_s),\n            "precision": (precision or "day").lower(),\n            "severity": severity_int,\n            "notes": notes,\n        })\n\n    return items\n\n\n\ndef make_empty_health_rows(count: int = 8) -> List[dict]:\n    rows = []\n    defaults = ["مرض وراثي", "عاهة خلقية", "عملية جراحية كبرى", "السكري", "أمراض القلب", "حادث سير", "دخول مستشفى", "مشكلة في العمود الفقري"]\n    for i in range(count):\n        rows.append({\n            "enabled": False,\n            "type": defaults[i] if i < len(defaults) else HEALTH_OPTIONS[0],\n            "date_text": "birth" if i < 2 else "",\n            "precision": "birth" if i < 2 else "day",\n            "severity": "5" if i < 2 else "3",\n            "notes": "",\n        })\n    return rows\n\n\ndef make_empty_event_rows(count: int = 10) -> List[dict]:\n    rows = []\n    defaults = ["زواج", "ولادة أول طفل", "وفاة الأب", "وفاة الأم", "تعيين", "سفر مهم", "شراء بيت", "طلاق", "ترقية", "خسارة مالية كبيرة"]\n    for i in range(count):\n        rows.append({\n            "enabled": False,\n            "type": defaults[i] if i < len(defaults) else EVENT_OPTIONS[0],\n            "date_text": "",\n            "precision": "day",\n            "severity": "5" if i < 4 else "4",\n            "notes": "",\n        })\n    return rows\n\n\n\ndef make_blank_health_rows(count: int = 8) -> List[dict]:\n    rows = []\n    for _ in range(count):\n        rows.append({\n            "enabled": False,\n            "type": HEALTH_OPTIONS[0],\n            "date_text": "",\n            "precision": "day",\n            "severity": "3",\n            "notes": "",\n        })\n    return rows\n\n\ndef make_blank_event_rows(count: int = 10) -> List[dict]:\n    rows = []\n    for _ in range(count):\n        rows.append({\n            "enabled": False,\n            "type": EVENT_OPTIONS[0],\n            "date_text": "",\n            "precision": "day",\n            "severity": "3",\n            "notes": "",\n        })\n    return rows\n\n\ndef rows_from_form(prefix: str, count: int, default_kind: str) -> List[dict]:\n    rows = []\n    for i in range(count):\n        rows.append({\n            "enabled": request.form.get(f"{prefix}_enabled_{i}") == "on",\n            "type": request.form.get(f"{prefix}_type_{i}", ""),\n            "date_text": request.form.get(f"{prefix}_date_{i}", ""),\n            "precision": request.form.get(f"{prefix}_precision_{i}", "day"),\n            "severity": request.form.get(f"{prefix}_severity_{i}", "3"),\n            "notes": request.form.get(f"{prefix}_notes_{i}", ""),\n        })\n    return rows\n\n\ndef selected_rows_to_items(rows: List[dict], default_kind: str) -> List[dict]:\n    items = []\n    for row in rows:\n        if not row.get("enabled"):\n            continue\n\n        item_type = (row.get("type") or "").strip()\n        date_s = (row.get("date_text") or "").strip()\n        precision = (row.get("precision") or "day").strip().lower()\n        notes = (row.get("notes") or "").strip()\n\n        try:\n            severity_int = int(float(row.get("severity") or 3))\n            severity_int = max(1, min(5, severity_int))\n        except Exception:\n            severity_int = 3\n\n        if precision == "birth" and not date_s:\n            date_s = "birth"\n\n        items.append({\n            "kind": default_kind,\n            "type": item_type or ("حالة صحية" if default_kind == "health" else "حدث"),\n            "date_text": date_s,\n            "date": parse_date_value(date_s),\n            "precision": precision,\n            "severity": severity_int,\n            "notes": notes,\n        })\n\n    return items\n\n\ndef time_range_minutes(start_time: str, end_time: str) -> int:\n    try:\n        s = datetime.strptime(start_time.strip(), "%H:%M")\n        e = datetime.strptime(end_time.strip(), "%H:%M")\n        if e < s:\n            e += timedelta(days=1)\n        return int((e - s).total_seconds() // 60)\n    except Exception:\n        return 999999\n\n\ndef validate_minimum_inputs(health_items: List[dict], event_items: List[dict], start_time: str, end_time: str) -> List[str]:\n    errors = []\n\n    if len(health_items) < 1:\n        errors.append("يجب اختيار حالة صحية واحدة على الأقل.")\n\n    if len(event_items) < 2:\n        errors.append("يجب اختيار حدثين عميقين على الأقل.")\n\n    all_items = health_items + event_items\n    has_precise_day = any(\n        item.get("precision") == "day" and bool(item.get("date"))\n        for item in all_items\n    )\n    has_birth_health = any(\n        item.get("kind") == "health" and item.get("precision") == "birth"\n        for item in health_items\n    )\n\n    if not (has_precise_day or has_birth_health):\n        errors.append("يجب وجود تاريخ دقيق واحد باليوم على الأقل، أو حالة صحية منذ الولادة.")\n\n    if time_range_minutes(start_time, end_time) > 240:\n        errors.append("في هذه النسخة يجب ألا يتجاوز مجال البحث 4 ساعات.")\n\n    return errors\n\n\ndef data_quality_label(health_items: List[dict], event_items: List[dict]) -> str:\n    total = len(health_items) + len(event_items)\n    if total >= 7:\n        return "قوي"\n    if total >= 5:\n        return "جيد"\n    if total >= 3:\n        return "مقبول مبدئيًا"\n    return "غير كافٍ"\n\n\n\ndef data_cap_from_witness_count(total_witnesses: int) -> int:\n    """\n    سقف الدرجة النهائية حسب عدد الشواهد.\n    الهدف: منع البيانات القليلة من إعطاء درجة مرتفعة مضللة.\n    """\n    if total_witnesses >= 7:\n        return 100\n    if total_witnesses == 6:\n        return 92\n    if total_witnesses == 5:\n        return 85\n    if total_witnesses == 4:\n        return 80\n    if total_witnesses == 3:\n        return 70\n    return 50\n\n\ndef support_level_from_fraction(value: float, maximum: float) -> str:\n    if maximum <= 0:\n        return "غير كافٍ"\n    ratio = value / maximum\n    if ratio >= 0.85:\n        return "قوي جدًا"\n    if ratio >= 0.65:\n        return "قوي"\n    if ratio >= 0.40:\n        return "متوسط"\n    if ratio > 0:\n        return "ضعيف"\n    return "لا يوجد دعم"\n\n\ndef score_level_from_100(score: float) -> str:\n    if score >= 85:\n        return "عالية جدًا"\n    if score >= 70:\n        return "عالية"\n    if score >= 55:\n        return "متوسطة"\n    if score >= 40:\n        return "ضعيفة إلى متوسطة"\n    return "ضعيفة"\n\n\ndef normalized_score_block(result: dict, all_results: List[dict], meta: dict) -> dict:\n    """\n    يحول النقاط الخام المفتوحة إلى نظام ثابت من 100:\n    - المحور الصحي: 35\n    - الأحداث العميقة: 50\n    - التناسق العام: 15\n    ثم يطبق سقفًا حسب عدد الشواهد.\n    """\n    max_health_raw = max([abs(r.get("health_score", 0.0)) for r in all_results] + [1.0])\n    max_event_raw = max([abs(r.get("event_score", 0.0)) for r in all_results] + [1.0])\n\n    health_raw = max(0.0, result.get("health_score", 0.0))\n    event_raw = max(0.0, result.get("event_score", 0.0))\n\n    health_35 = min(35.0, (health_raw / max_health_raw) * 35.0) if max_health_raw else 0.0\n    event_50 = min(50.0, (event_raw / max_event_raw) * 50.0) if max_event_raw else 0.0\n\n    # التناسق: يرتفع عندما يدعم المحوران النتيجة معًا بدل اعتمادها على محور واحد.\n    h_ratio = health_35 / 35.0 if 35 else 0.0\n    e_ratio = event_50 / 50.0 if 50 else 0.0\n    consistency_15 = min(h_ratio, e_ratio) * 15.0\n\n    raw_100 = health_35 + event_50 + consistency_15\n\n    total_witnesses = int(meta.get("health_count") or 0) + int(meta.get("event_count") or 0)\n    cap = data_cap_from_witness_count(total_witnesses)\n    final_100 = min(raw_100, float(cap))\n\n    return {\n        "health_35": health_35,\n        "event_50": event_50,\n        "consistency_15": consistency_15,\n        "raw_100": raw_100,\n        "cap": cap,\n        "final_100": final_100,\n        "level": score_level_from_100(final_100),\n        "health_level": support_level_from_fraction(health_35, 35.0),\n        "event_level": support_level_from_fraction(event_50, 50.0),\n        "consistency_level": support_level_from_fraction(consistency_15, 15.0),\n    }\n\n\ndef detail_distribution_lines(details: List[dict], total_score_100: float) -> List[str]:\n    """\n    يعرض مساهمة كل شاهد بصيغة واضحة:\n    الزواج: 12.4 / 76.0\n    """\n    if not details:\n        return ["لا توجد تفاصيل كافية لتوزيع النقاط."]\n\n    positive = [d for d in details if d.get("score", 0) > 0]\n    if not positive:\n        return ["لا توجد نقاط إيجابية كافية لتوزيعها."]\n\n    raw_sum = sum(d.get("score", 0.0) for d in positive)\n    if raw_sum <= 0:\n        return ["لا توجد نقاط إيجابية كافية لتوزيعها."]\n\n    grouped = {}\n    for d in positive:\n        label = d.get("item", "شاهد")\n        axis = d.get("axis", "")\n        if axis == "الصحة":\n            label = f"المحور الصحي: {label}"\n        grouped[label] = grouped.get(label, 0.0) + d.get("score", 0.0)\n\n    lines = []\n    for label, raw in sorted(grouped.items(), key=lambda x: x[1], reverse=True):\n        part = (raw / raw_sum) * total_score_100 if total_score_100 > 0 else 0.0\n        level = support_level_from_fraction(part, max(total_score_100, 1.0))\n        lines.append(f"{label}: {part:.1f} / {total_score_100:.1f} — دعم {level}")\n\n    return lines\n\n\ndef build_minutes(start_time_s: str, end_time_s: str) -> List[str]:\n    s = datetime.strptime(start_time_s.strip(), "%H:%M")\n    e = datetime.strptime(end_time_s.strip(), "%H:%M")\n\n    if e < s:\n        e += timedelta(days=1)\n\n    out = []\n    current = s\n    while current <= e:\n        out.append(current.strftime("%H:%M"))\n        current += timedelta(minutes=1)\n\n    return out\n\n\ndef date_to_jd_ut(local_dt: datetime, tz_hours: float) -> float:\n    dt_utc = local_dt - timedelta(hours=tz_hours)\n    hour = dt_utc.hour + dt_utc.minute / 60.0 + dt_utc.second / 3600.0\n    return swe.julday(dt_utc.year, dt_utc.month, dt_utc.day, hour)\n\n\ndef age_in_years(birth_dt: datetime, event_dt: Optional[datetime]) -> float:\n    if not event_dt:\n        return 0.0\n    return max(0.0, (event_dt - birth_dt).days / 365.2425)\n\n\ndef normalize_house_cusps(cusps_raw) -> Dict[int, float]:\n    """\n    swisseph يرجع cusps غالبًا 13 قيمة، البيت 1 في index 1.\n    أحيانًا حسب البيئة قد يأتي بشكل مختلف؛ لذلك نعالجه بحذر.\n    """\n    if len(cusps_raw) >= 13:\n        return {i: norm360(cusps_raw[i]) for i in range(1, 13)}\n    return {i + 1: norm360(cusps_raw[i]) for i in range(12)}\n\n\nclass RectificationEngine:\n    def __init__(self, birth_date: datetime, lat: float, lon: float, tz_hours: float):\n        if swe is None:\n            raise RuntimeError("مكتبة pyswisseph غير مثبتة. ثبّتها بالأمر: pip install pyswisseph")\n        self.birth_date = birth_date\n        self.lat = float(lat)\n        self.lon = float(lon)\n        self.tz_hours = float(tz_hours)\n\n    def calc_chart(self, local_dt: datetime) -> dict:\n        jd = date_to_jd_ut(local_dt, self.tz_hours)\n\n        # Placidus\n        cusps_raw, ascmc = swe.houses_ex(jd, self.lat, self.lon, b\'P\')\n        houses = normalize_house_cusps(cusps_raw)\n\n        asc = norm360(ascmc[0])\n        mc = norm360(ascmc[1])\n\n        planets = {}\n        speeds = {}\n\n        for pname, pid in PLANET_IDS.items():\n            try:\n                pos = swe.calc_ut(jd, pid)[0]\n                planets[pname] = norm360(pos[0])\n                speeds[pname] = pos[3]\n            except Exception:\n                pass\n\n        rulers = {h: sign_ruler(deg) for h, deg in houses.items()}\n\n        return {\n            "jd": jd,\n            "local_dt": local_dt,\n            "asc": asc,\n            "mc": mc,\n            "houses": houses,\n            "rulers": rulers,\n            "planets": planets,\n            "speeds": speeds,\n            "asc_term": ptolemy_term(asc),\n            "asc_ruler": sign_ruler(asc),\n        }\n\n    def planet_house(self, deg: float, houses: Dict[int, float]) -> int:\n        d = norm360(deg)\n        cusps = [houses[i] for i in range(1, 13)]\n\n        for i in range(12):\n            start = cusps[i]\n            end = cusps[(i + 1) % 12]\n\n            if start <= end:\n                if start <= d < end:\n                    return i + 1\n            else:\n                if d >= start or d < end:\n                    return i + 1\n\n        return 1\n\n    def natal_health_score(self, chart: dict, item: dict) -> Tuple[float, List[str]]:\n        severity = item["severity"]\n        score = 0.0\n        reasons = []\n\n        asc = chart["asc"]\n        planets = chart["planets"]\n        houses = chart["houses"]\n        rulers = chart["rulers"]\n        asc_ruler = chart["asc_ruler"]\n\n        for p in HEALTH_PLANETS:\n            if p in planets:\n                sc, asp, delta = aspect_score(planets[p], asc, base_weight=10 * severity, hard_only=True)\n                if sc:\n                    score += sc\n                    reasons.append(f"{p} {asp} الطالع بفارق {delta:.2f}°")\n\n        for p in HEALTH_PLANETS:\n            if p in planets:\n                h = self.planet_house(planets[p], houses)\n                if h in HEALTH_HOUSES:\n                    add = 5 * severity\n                    score += add\n                    reasons.append(f"{p} في البيت {h}")\n\n        if asc_ruler in planets:\n            for h in [6, 8, 12]:\n                ruler = rulers.get(h)\n                if ruler in planets:\n                    sc, asp, delta = aspect_score(planets[asc_ruler], planets[ruler], base_weight=8 * severity, hard_only=True)\n                    if sc:\n                        score += sc\n                        reasons.append(f"حاكم الطالع {asc_ruler} {asp} حاكم البيت {h} {ruler} بفارق {delta:.2f}°")\n\n        term_ruler = chart["asc_term"]\n        if term_ruler in ["زحل", "المريخ"] and any(word in item["type"] for word in ["مرض", "عاهة", "عملية", "حادث", "وراث", "خلقي"]):\n            score += 7 * severity\n            reasons.append(f"الطالع في حد {term_ruler} مناسب لمحور صحي قوي")\n\n        return score, reasons\n\n    def timed_health_score(self, natal_chart: dict, event_dt: Optional[datetime], item: dict) -> Tuple[float, List[str]]:\n        if not event_dt:\n            return 0.0, []\n\n        severity = item["severity"]\n        birth_dt = self.birth_date\n        age = age_in_years(birth_dt, event_dt)\n\n        score = 0.0\n        reasons = []\n\n        # Solar Arc approximation: Sun progression about 1 degree/year.\n        arc = age\n\n        natal_points = {\n            "الطالع": natal_chart["asc"],\n            "MC": natal_chart["mc"],\n            "رأس السادس": natal_chart["houses"][6],\n            "رأس الثامن": natal_chart["houses"][8],\n            "رأس الثاني عشر": natal_chart["houses"][12],\n        }\n\n        for label, deg in natal_points.items():\n            sa_deg = norm360(deg + arc)\n            for target_name in ["الطالع", "رأس السادس", "رأس الثامن", "رأس الثاني عشر"]:\n                target = natal_points[target_name]\n                sc, asp, delta = aspect_score(sa_deg, target, base_weight=5 * severity, hard_only=True, max_orb_override=1.2)\n                if sc:\n                    score += sc\n                    reasons.append(f"القوس الشمسي لـ {label} {asp} {target_name} بفارق {delta:.2f}°")\n\n        # Transits at event date, noon local\n        try:\n            event_chart = self.calc_chart(event_dt.replace(hour=12, minute=0, second=0, microsecond=0))\n            for p in ["زحل", "المريخ", "بلوتو", "نبتون", "كيرون"]:\n                if p in event_chart["planets"]:\n                    for label, target in natal_points.items():\n                        sc, asp, delta = aspect_score(event_chart["planets"][p], target, base_weight=4 * severity, hard_only=True)\n                        if sc:\n                            score += sc\n                            reasons.append(f"عبور {p} {asp} {label} بفارق {delta:.2f}°")\n        except Exception:\n            pass\n\n        return score, reasons\n\n    def event_profile(self, event_type: str) -> dict:\n        t = event_type or ""\n\n        if any(k in t for k in ["زواج", "ارتباط", "عقد"]):\n            return {"houses": [1, 4, 7, 10], "planets": ["الزهرة", "القمر", "المشتري"], "name": "زواج/ارتباط رسمي"}\n\n        if any(k in t for k in ["طلاق", "انفصال"]):\n            return {"houses": [1, 7, 8, 12], "planets": ["المريخ", "زحل", "أورانوس", "بلوتو"], "name": "طلاق/انفصال"}\n\n        if any(k in t for k in ["ولادة", "طفل", "حمل"]):\n            return {"houses": [4, 5, 8, 10], "planets": ["القمر", "الزهرة", "المشتري"], "name": "ولادة/أطفال"}\n\n        if any(k in t for k in ["وفاة", "موت", "فقد"]):\n            return {"houses": [4, 8, 10, 12], "planets": ["زحل", "المريخ", "بلوتو", "القمر"], "name": "وفاة/فقد"}\n\n        if any(k in t for k in ["تعيين", "وظيفة", "عمل", "ترقية", "منصب"]):\n            return {"houses": [2, 6, 10, 11], "planets": ["الشمس", "زحل", "المشتري", "عطارد"], "name": "عمل/منصب"}\n\n        if any(k in t for k in ["سفر", "هجرة", "انتقال بلد"]):\n            return {"houses": [3, 4, 9, 12], "planets": ["عطارد", "المشتري", "القمر", "أورانوس"], "name": "سفر/هجرة"}\n\n        if any(k in t for k in ["بيت", "سكن", "عقار", "سيارة", "شراء"]):\n            return {"houses": [2, 3, 4, 8], "planets": ["الزهرة", "القمر", "المشتري", "زحل"], "name": "شراء/سكن/ممتلكات"}\n\n        if any(k in t for k in ["خسارة", "مال", "ربح", "دين"]):\n            return {"houses": [2, 8, 11, 12], "planets": ["الزهرة", "المشتري", "زحل", "بلوتو"], "name": "مال"}\n\n        if any(k in t for k in ["مرض", "عملية", "حادث", "مستشفى"]):\n            return {"houses": [1, 6, 8, 12], "planets": ["زحل", "المريخ", "القمر", "بلوتو"], "name": "حدث صحي"}\n\n        return {"houses": [1, 4, 7, 10], "planets": ["الشمس", "القمر", "زحل", "المشتري"], "name": "حدث عميق عام"}\n\n    def timed_event_score(self, natal_chart: dict, event_dt: Optional[datetime], item: dict) -> Tuple[float, List[str]]:\n        if not event_dt:\n            return 0.0, []\n\n        severity = item["severity"]\n        profile = self.event_profile(item["type"])\n        age = age_in_years(self.birth_date, event_dt)\n        arc = age\n\n        score = 0.0\n        reasons = []\n\n        houses = natal_chart["houses"]\n        planets = natal_chart["planets"]\n        rulers = natal_chart["rulers"]\n\n        event_points = {}\n        for h in profile["houses"]:\n            event_points[f"رأس البيت {h}"] = houses[h]\n            r = rulers.get(h)\n            if r in planets:\n                event_points[f"حاكم البيت {h} {r}"] = planets[r]\n\n        for p in profile["planets"]:\n            if p in planets:\n                event_points[p] = planets[p]\n\n        natal_core = {\n            "الطالع": natal_chart["asc"],\n            "MC": natal_chart["mc"],\n            "الشمس": planets.get("الشمس"),\n            "القمر": planets.get("القمر"),\n            "الزهرة": planets.get("الزهرة"),\n            "المريخ": planets.get("المريخ"),\n        }\n        natal_core = {k: v for k, v in natal_core.items() if v is not None}\n\n        for label, deg in natal_core.items():\n            sa_deg = norm360(deg + arc)\n            for target_label, target in event_points.items():\n                sc, asp, delta = aspect_score(sa_deg, target, base_weight=4.5 * severity, hard_only=True, max_orb_override=1.2)\n                if sc:\n                    score += sc\n                    reasons.append(f"القوس الشمسي لـ {label} {asp} {target_label} بفارق {delta:.2f}°")\n\n        precision = item["precision"]\n        if precision == "day":\n            transit_weight = 3.5\n        elif precision == "month":\n            transit_weight = 2.0\n        else:\n            transit_weight = 1.0\n\n        try:\n            event_chart = self.calc_chart(event_dt.replace(hour=12, minute=0, second=0, microsecond=0))\n            for p in list(dict.fromkeys(profile["planets"] + ["زحل", "المريخ", "المشتري"])):\n                if p in event_chart["planets"]:\n                    for target_label, target in event_points.items():\n                        sc, asp, delta = aspect_score(event_chart["planets"][p], target, base_weight=transit_weight * severity, hard_only=False)\n                        if sc:\n                            score += sc\n                            reasons.append(f"عبور {p} {asp} {target_label} بفارق {delta:.2f}°")\n        except Exception:\n            pass\n\n        term_ruler = natal_chart["asc_term"]\n        if term_ruler in profile["planets"]:\n            add = 4 * severity\n            score += add\n            reasons.append(f"صاحب حد الطالع {term_ruler} من كواكب الحدث")\n\n        return score, reasons\n\n    def score_candidate(self, time_s: str, health_items: List[dict], event_items: List[dict]) -> dict:\n        h, m = [int(x) for x in time_s.split(":")]\n        local_dt = self.birth_date.replace(hour=h, minute=m, second=0, microsecond=0)\n        chart = self.calc_chart(local_dt)\n\n        total = 0.0\n        health_total = 0.0\n        event_total = 0.0\n        details = []\n\n        for item in health_items:\n            item_score = 0.0\n            item_reasons = []\n\n            is_birth_case = (\n                item["precision"] == "birth"\n                or item["date"] is None\n                or str(item["date_text"]).lower() in ["birth", "ولادة", "منذ الولادة"]\n            )\n\n            if is_birth_case:\n                sc, rs = self.natal_health_score(chart, item)\n                item_score += sc\n                item_reasons += rs\n            else:\n                sc1, rs1 = self.natal_health_score(chart, item)\n                sc2, rs2 = self.timed_health_score(chart, item["date"], item)\n                item_score += sc1 * 0.35 + sc2\n                item_reasons += rs1[:3] + rs2\n\n            health_total += item_score\n            if item_reasons:\n                details.append({\n                    "axis": "الصحة",\n                    "item": item["type"],\n                    "score": item_score,\n                    "reasons": item_reasons[:8],\n                })\n\n        for item in event_items:\n            sc, rs = self.timed_event_score(chart, item["date"], item)\n            event_total += sc\n            if rs:\n                details.append({\n                    "axis": "الأحداث",\n                    "item": item["type"],\n                    "score": sc,\n                    "reasons": rs[:8],\n                })\n\n        strong_health = [i for i in health_items if i["severity"] >= 4]\n        if strong_health and health_total < 8:\n            total -= 18\n            details.append({\n                "axis": "استبعاد",\n                "item": "فشل صحي",\n                "score": -18,\n                "reasons": ["وجود حالة صحية قوية لكن الوقت لم يعط دعمًا كافيًا للطالع/السادس/الثامن/الثاني عشر"],\n            })\n\n        total += health_total + event_total\n        total += health_total * 0.25\n\n        return {\n            "time": time_s,\n            "score": total,\n            "health_score": health_total,\n            "event_score": event_total,\n            "chart": chart,\n            "details": details,\n        }\n\n    def run_all(self, start_time: str, end_time: str, health_items: List[dict], event_items: List[dict]) -> List[dict]:\n        candidates = []\n        for time_s in build_minutes(start_time, end_time):\n            try:\n                candidates.append(self.score_candidate(time_s, health_items, event_items))\n            except Exception:\n                # نحافظ على استمرار الفحص حتى لو فشل وقت واحد\n                pass\n\n        candidates.sort(key=lambda x: x["score"], reverse=True)\n        return candidates\n\n    def run(self, start_time: str, end_time: str, health_items: List[dict], event_items: List[dict], top_n: int = 5) -> List[dict]:\n        return self.run_all(start_time, end_time, health_items, event_items)[:top_n]\n\n\ndef confidence_label(score: float) -> str:\n    if score >= 220:\n        return "عالية جدًا"\n    if score >= 150:\n        return "عالية"\n    if score >= 90:\n        return "متوسطة"\n    if score >= 45:\n        return "ضعيفة إلى متوسطة"\n    return "ضعيفة"\n\n\ndef chart_summary(chart: dict) -> str:\n    lines = []\n    lines.append(f"الطالع: {format_degree(chart[\'asc\'])}")\n    lines.append(f"MC: {format_degree(chart[\'mc\'])}")\n    lines.append(f"حاكم الطالع: {chart[\'asc_ruler\']}")\n    lines.append(f"صاحب حد الطالع: {chart[\'asc_term\']}")\n    lines.append("")\n    lines.append("رؤوس البيوت Placidus:")\n    for i in range(1, 13):\n        lines.append(f"البيت {i}: {format_degree(chart[\'houses\'][i])}")\n    lines.append("")\n    lines.append("مواقع الكواكب:")\n    for p, d in chart["planets"].items():\n        sp = chart["speeds"].get(p)\n        motion = ""\n        if sp is not None:\n            motion = " متراجع" if sp < 0 else " مباشر"\n        lines.append(f"{p}: {format_degree(d)}{motion}")\n    return "\\n".join(lines)\n\n\ndef general_notes_after_rectification(chart: dict) -> str:\n    asc = chart["asc"]\n    asc_sign = SIGNS_AR[sign_index(asc)]\n    asc_ruler = chart["asc_ruler"]\n    term = chart["asc_term"]\n\n    notes = []\n    notes.append("الملاحظات العامة بعد تصحيح الطالع:")\n    notes.append(f"الطالع المصحح يقع في {format_degree(asc)}.")\n    notes.append(f"البرج الصاعد هو {asc_sign}، وحاكم الطالع التقليدي هو {asc_ruler}.")\n    notes.append(f"صاحب حد الطالع هو {term}.")\n\n    descriptions = {\n        "العقرب": "يميل الوصف العام إلى العمق، الكتمان، قوة التحمل، الحس الأمني، وشدة الملاحظة.",\n        "الميزان": "يميل الوصف العام إلى العلاقات، التوازن، الذوق، وحساب ردود فعل الآخرين.",\n        "العذراء": "يميل الوصف العام إلى التحليل، الدقة، الخدمة، مراقبة التفاصيل، والحس الصحي.",\n        "الجدي": "يميل الوصف العام إلى الجدية، المسؤولية، الحذر، وبناء المكانة تدريجيًا.",\n        "الحمل": "يميل الوصف العام إلى المبادرة، السرعة، الجرأة، والاستجابة المباشرة للمواقف.",\n        "الثور": "يميل الوصف العام إلى الثبات، الحس العملي، التعلق بالأمان، والهدوء الظاهري.",\n        "الجوزاء": "يميل الوصف العام إلى الحركة، الكلام، الفضول، وسرعة الالتقاط.",\n        "السرطان": "يميل الوصف العام إلى الحس العائلي، الذاكرة، الحماية، وتقلب المزاج حسب الأمان الداخلي.",\n        "الأسد": "يميل الوصف العام إلى الحضور، الكرامة، الرغبة في الاعتراف، والقيادة الظاهرة.",\n        "القوس": "يميل الوصف العام إلى التوسع، السفر، المعنى، الصراحة، والبحث عن أفق أوسع.",\n        "الدلو": "يميل الوصف العام إلى الاستقلال، التفكير المختلف، العلاقات الجماعية، والتمرد الهادئ.",\n        "الحوت": "يميل الوصف العام إلى الحساسية، الخيال، الالتقاط النفسي، والتأثر بالمحيط.",\n    }\n\n    notes.append(descriptions.get(asc_sign, ""))\n\n    return "\\n".join(notes)\n\n\ndef cluster_top_results(results: List[dict], max_gap_minutes: int = 5) -> dict:\n    """\n    يحوّل النتائج المتقاربة إلى نطاق واحد مفهوم للمستخدم.\n    """\n    if not results:\n        return {}\n\n    def to_minutes(t: str) -> int:\n        h, m = [int(x) for x in t.split(":")]\n        return h * 60 + m\n\n    best = results[0]\n    best_score = best.get("score", 0)\n    close = []\n    for r in results:\n        # ندخل النتائج القريبة زمنيًا من أفضل نتيجة، والمتقاربة جدًا بالنقاط.\n        if abs(to_minutes(r["time"]) - to_minutes(best["time"])) <= max_gap_minutes:\n            close.append(r)\n\n    if not close:\n        close = [best]\n\n    times = sorted([r["time"] for r in close])\n    asc_values = [r["chart"]["asc"] for r in close]\n\n    return {\n        "best": best,\n        "start_time": times[0],\n        "end_time": times[-1],\n        "asc_min": min(asc_values),\n        "asc_max": max(asc_values),\n        "count": len(close),\n    }\n\n\ndef build_user_report(results: List[dict], meta: dict, all_results: Optional[List[dict]] = None) -> str:\n    if not results:\n        return "لم يتم استخراج نتائج. تأكد من البيانات المدخلة."\n\n    if all_results is None:\n        all_results = results\n\n    best = results[0]\n    ch = best["chart"]\n    ns = normalized_score_block(best, all_results, meta)\n    cluster = cluster_top_results(results)\n    total_witnesses = int(meta.get("health_count") or 0) + int(meta.get("event_count") or 0)\n\n    lines = []\n    lines.append("نتيجة تصحيح الميلاد")\n    lines.append("=" * 34)\n    lines.append(f"الاسم: {meta.get(\'name\', \'\')}")\n    lines.append(f"الدولة والمدينة: {meta.get(\'country\', \'\')} - {meta.get(\'city\', \'\')}")\n    lines.append(f"مجال البحث الذي تم فحصه: من {meta.get(\'start_time\')} إلى {meta.get(\'end_time\')}")\n    lines.append("")\n\n    if cluster:\n        if cluster["start_time"] == cluster["end_time"]:\n            lines.append(f"الوقت الأقرب للولادة: {best[\'time\']}")\n        else:\n            lines.append(f"النطاق الأقوى للولادة: من {cluster[\'start_time\']} إلى {cluster[\'end_time\']}")\n            lines.append(f"أفضل دقيقة داخل النطاق: {best[\'time\']}")\n\n    lines.append(f"الطالع المرجح: {format_degree(ch[\'asc\'])}")\n    lines.append(f"درجة التصحيح: {ns[\'final_100\']:.1f} / 100")\n    lines.append(f"درجة الاعتماد: {ns[\'level\']}")\n    lines.append("")\n\n    lines.append("كفاية البيانات:")\n    lines.append(f"عدد الحالات الصحية المختارة: {meta.get(\'health_count\')}")\n    lines.append(f"عدد الأحداث المهمة المختارة: {meta.get(\'event_count\')}")\n    lines.append(f"مجموع الشواهد: {total_witnesses}")\n    lines.append(f"تقييم كفاية البيانات: {meta.get(\'data_quality\')}")\n    lines.append(f"أعلى درجة ممكنة لهذه البيانات: {ns[\'cap\']} / 100")\n    lines.append("")\n\n    lines.append("سبب ترجيح هذا الوقت:")\n    lines.append(\n        "هذا الوقت ظهر كأقوى نتيجة لأنه جمع دعمًا واضحًا من المحور الصحي ومن الأحداث المهمة المدخلة، "\n        "كما أن النتائج القريبة منه تكررت ضمن نطاق زمني ضيق، وهذا يجعل هذا المجال أقوى من بقية الأوقات داخل مجال البحث."\n    )\n    lines.append("")\n\n    lines.append("ملخص الدعم:")\n    lines.append(f"المحور الصحي: {ns[\'health_35\']:.1f} / 35")\n    lines.append(f"الأحداث المهمة: {ns[\'event_50\']:.1f} / 50")\n    lines.append(f"تناسق الشواهد معًا: {ns[\'consistency_15\']:.1f} / 15")\n    lines.append("")\n\n    lines.append("ملاحظات مهمة:")\n    lines.append("درجة التصحيح لا تعني يقينًا مطلقًا، بل تعني أن هذا الوقت هو الأقوى بين الأوقات التي تم فحصها وفق البيانات المدخلة.")\n    lines.append("إذا أضيفت شواهد جديدة، خصوصًا أحداث دقيقة التاريخ أو حالات صحية مؤكدة، فقد تتغير الدرجة أو يضيق نطاق التصحيح أكثر.")\n    lines.append("")\n\n    lines.append("الملاحظات العامة بعد التصحيح:")\n    asc = ch["asc"]\n    asc_sign = SIGNS_AR[sign_index(asc)]\n    lines.append(f"الطالع المرجح في {asc_sign}.")\n    if asc_sign == "العقرب":\n        lines.append("يشير ذلك إلى شخصية عميقة، قوية الملاحظة، تميل إلى الكتمان والتحمل، ولا تكشف ما بداخلها بسهولة.")\n    elif asc_sign == "الميزان":\n        lines.append("يشير ذلك إلى شخصية تبحث عن التوازن، تهتم بالعلاقات، وتفكر كثيرًا في ردود فعل الآخرين.")\n    elif asc_sign == "العذراء":\n        lines.append("يشير ذلك إلى شخصية دقيقة، تحليلية، تهتم بالتفاصيل، وقد يكون لديها حس صحي أو عملي واضح.")\n    elif asc_sign == "الجدي":\n        lines.append("يشير ذلك إلى شخصية جدية، مسؤولة، تميل إلى الحذر وبناء المكانة خطوة بعد خطوة.")\n    elif asc_sign == "الحمل":\n        lines.append("يشير ذلك إلى شخصية مباشرة، سريعة المبادرة، وتميل إلى المواجهة والقرار السريع.")\n    elif asc_sign == "الثور":\n        lines.append("يشير ذلك إلى شخصية ثابتة، عملية، تبحث عن الأمان والاستقرار.")\n    elif asc_sign == "الجوزاء":\n        lines.append("يشير ذلك إلى شخصية متحركة، فضولية، سريعة الكلام أو التفكير، ومتعددة الاهتمامات.")\n    elif asc_sign == "السرطان":\n        lines.append("يشير ذلك إلى شخصية حساسة، عائلية، قوية الذاكرة، وتتأثر بالأمان العاطفي.")\n    elif asc_sign == "الأسد":\n        lines.append("يشير ذلك إلى شخصية ذات حضور، تحب الاعتراف بقيمتها، وتميل إلى الكرامة والقيادة.")\n    elif asc_sign == "القوس":\n        lines.append("يشير ذلك إلى شخصية تبحث عن التوسع، السفر، المعنى، والأفق الأوسع.")\n    elif asc_sign == "الدلو":\n        lines.append("يشير ذلك إلى شخصية مستقلة، مختلفة التفكير، وتميل إلى الحرية والجماعات.")\n    elif asc_sign == "الحوت":\n        lines.append("يشير ذلك إلى شخصية حساسة، خيالية، تلتقط الأجواء النفسية وتتأثر بالمحيط.")\n\n    return "\\n".join(lines)\n\n\ndef build_developer_report(results: List[dict], meta: dict, all_results: Optional[List[dict]] = None) -> str:\n    if not results:\n        return "لم يتم استخراج نتائج فنية."\n\n    if all_results is None:\n        all_results = results\n\n    lines = []\n    lines.append("التقرير الفني للمطور والباحث")\n    lines.append("=" * 50)\n    lines.append("هذا التقرير مخصص للمراجعة الفنية ولا يُفترض عرضه للمستخدم العادي.")\n    lines.append("")\n    lines.append(f"الاسم: {meta.get(\'name\', \'\')}")\n    lines.append(f"الدولة: {meta.get(\'country\', \'\')}")\n    lines.append(f"المدينة: {meta.get(\'city\', \'\')}")\n    lines.append(f"الإحداثيات: خط العرض {meta.get(\'lat\')} / خط الطول {meta.get(\'lon\')}")\n    lines.append(f"فرق التوقيت المستخدم: GMT {meta.get(\'tz\'):+g}")\n    lines.append(f"نظام البيوت: Placidus")\n    lines.append(f"مجال البحث المفحوص: من {meta.get(\'start_time\')} إلى {meta.get(\'end_time\')}")\n    lines.append(f"عدد الحالات الصحية المختارة: {meta.get(\'health_count\')}")\n    lines.append(f"عدد الأحداث المختارة: {meta.get(\'event_count\')}")\n    total_witnesses = int(meta.get("health_count") or 0) + int(meta.get("event_count") or 0)\n    cap = data_cap_from_witness_count(total_witnesses)\n    lines.append(f"عدد الشواهد الكلي: {total_witnesses}")\n    lines.append(f"درجة كفاية البيانات: {meta.get(\'data_quality\')}")\n    lines.append(f"سقف الدرجة حسب عدد الشواهد: {cap} / 100")\n    lines.append("")\n\n    cluster = cluster_top_results(results)\n    if cluster:\n        lines.append("ملاحظة نطاقية:")\n        lines.append(f"أفضل النتائج متقاربة ضمن النطاق: {cluster[\'start_time\']} - {cluster[\'end_time\']}")\n        lines.append(f"عدد النتائج داخل النطاق القريب: {cluster[\'count\']}")\n        lines.append(f"نطاق الطالع داخل النتائج القريبة: {format_degree(cluster[\'asc_min\'])} إلى {format_degree(cluster[\'asc_max\'])}")\n        lines.append("")\n\n    lines.append("نظام النقاط الفني:")\n    lines.append("درجة التصحيح النهائية من 100: الصحة 35، الأحداث 50، التناسق 15.")\n    lines.append("النقاط الخام تُستخدم داخليًا للمقارنة بين الأوقات داخل نفس الاختبار فقط.")\n    lines.append("")\n\n    for i, r in enumerate(results, 1):\n        ch = r["chart"]\n        ns = normalized_score_block(r, all_results, meta)\n\n        lines.append(f"النتيجة رقم {i}")\n        lines.append("-" * 36)\n        lines.append(f"الوقت المرشح: {r[\'time\']}")\n        lines.append(f"الطالع: {format_degree(ch[\'asc\'])}")\n        lines.append(f"MC: {format_degree(ch[\'mc\'])}")\n        lines.append(f"حاكم الطالع: {ch[\'asc_ruler\']}")\n        lines.append(f"صاحب حد الطالع: {ch[\'asc_term\']}")\n        lines.append("")\n\n        lines.append(f"درجة التصحيح النهائية: {ns[\'final_100\']:.1f} / 100")\n        lines.append(f"درجة الثقة: {ns[\'level\']}")\n        lines.append(f"السقف المطبق بسبب عدد الشواهد: {ns[\'cap\']} / 100")\n        lines.append("")\n        lines.append("توزيع الدرجة:")\n        lines.append(f"المحور الصحي: {ns[\'health_35\']:.1f} / 35 — دعم {ns[\'health_level\']}")\n        lines.append(f"الأحداث العميقة: {ns[\'event_50\']:.1f} / 50 — دعم {ns[\'event_level\']}")\n        lines.append(f"التناسق العام: {ns[\'consistency_15\']:.1f} / 15 — دعم {ns[\'consistency_level\']}")\n        lines.append("")\n        lines.append("توزيع النقاط حسب الشواهد:")\n        for line in detail_distribution_lines(r.get("details", []), ns["final_100"]):\n            # لا نضع كلمة دعم ضعيف هنا؛ نترك الرقم واضحًا فقط\n            clean = line.split(" — ")[0]\n            lines.append(clean)\n\n        lines.append("")\n        lines.append("النقاط الخام الداخلية للمراجعة:")\n        lines.append(f"مجموع النقاط الخام: {r[\'score\']:.2f}")\n        lines.append(f"دعم الصحة الخام: {r[\'health_score\']:.2f}")\n        lines.append(f"دعم الأحداث الخام: {r[\'event_score\']:.2f}")\n        lines.append("")\n\n        if r["details"]:\n            lines.append("تفاصيل الأدلة:")\n            details_sorted = sorted(r["details"], key=lambda x: x["score"], reverse=True)\n            for d in details_sorted[:10]:\n                if d["score"] <= 0:\n                    continue\n                lines.append(f"{d[\'item\']}:")\n                for reason in d["reasons"][:5]:\n                    lines.append(f"  • {reason}")\n        else:\n            lines.append("لم تظهر أسباب ترجيح كافية لهذا الوقت.")\n\n        lines.append("")\n\n        if i == 1:\n            lines.append("ملخص الخريطة للنتيجة الأولى:")\n            lines.append(chart_summary(ch))\n            lines.append("")\n            lines.append(general_notes_after_rectification(ch))\n            lines.append("")\n\n        lines.append("=" * 50)\n        lines.append("")\n\n    lines.append("ملاحظات فنية للمراجعة:")\n    lines.append("1. إذا كانت النتائج الخمس متقاربة جدًا زمنيًا، يُفضّل اعتمادها كنطاق لا كخمس نتائج منفصلة.")\n    lines.append("2. إذا تكرر نفس الدليل بسبب حاكم مشترك، يجب مراقبة احتمال تضخيم النقاط.")\n    lines.append("3. إذا كانت معظم الأحداث من نوع واحد، يُفضّل إضافة شاهد من نوع مختلف لتثبيت أدق.")\n    return "\\n".join(lines)\n\n\nHTML = r"""\n<!doctype html>\n<html lang="ar" dir="rtl">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1">\n<title>تصحيح الطالع</title>\n<style>\n:root{\n  --bg:#0f172a; --card:#111827; --soft:#1f2937; --line:#334155;\n  --text:#f8fafc; --muted:#cbd5e1; --accent:#f59e0b; --accent2:#38bdf8;\n}\n*{box-sizing:border-box}\nbody{\n  margin:0; font-family:Tahoma, Arial, sans-serif; background:linear-gradient(135deg,#020617,#0f172a,#111827);\n  color:var(--text); line-height:1.8;\n}\n.wrap{width:min(1100px,96%); margin:18px auto 42px}\n.hero,.card{\n  background:rgba(17,24,39,.94); border:1px solid var(--line); border-radius:22px; padding:18px;\n  box-shadow:0 12px 32px rgba(0,0,0,.28); margin-bottom:14px;\n}\nh1{margin:0 0 8px; font-size:25px; text-align:center}\nh2{font-size:19px; margin:0 0 12px; border-bottom:1px solid var(--line); padding-bottom:8px}\n.grid{display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:14px}\n.row{display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:10px}\n@media(max-width:760px){.grid,.row{grid-template-columns:1fr}}\nlabel{display:block; color:var(--muted); margin:9px 0 5px; font-size:14px}\ninput,textarea,select{\n  width:100%; border:1px solid #475569; background:#020617; color:#fff; border-radius:14px;\n  padding:11px 12px; font-size:15px; outline:none; font-family:Tahoma, Arial, sans-serif;\n}\ntextarea{min-height:145px; resize:vertical}\ninput:focus,textarea:focus,select:focus{border-color:var(--accent2); box-shadow:0 0 0 3px rgba(56,189,248,.15)}\nbutton{\n  border:none; border-radius:16px; padding:14px 18px; font-size:17px; font-weight:700;\n  cursor:pointer; font-family:Tahoma, Arial, sans-serif; width:100%; margin-top:12px;\n  background:linear-gradient(135deg,#f59e0b,#f97316); color:#111827;\n}\n.secondary{background:#1f2937; color:#fff; border:1px solid #475569}\n.clear-btn{\n  background:#1f2937;\n  color:#fff;\n  border:1px solid #ef4444;\n  margin:0;\n}\n.top-actions{\n  display:grid;\n  grid-template-columns:1fr 1fr;\n  gap:10px;\n  margin:0 0 14px 0;\n}\n.home-btn{\n  display:block;\n  text-align:center;\n  text-decoration:none;\n  border-radius:16px;\n  padding:14px 18px;\n  font-size:17px;\n  font-weight:700;\n  font-family:Tahoma, Arial, sans-serif;\n  background:#1f2937;\n  color:#fff;\n  border:1px solid #475569;\n}\n@media(max-width:520px){.top-actions{grid-template-columns:1fr}}\n.hint{color:#94a3b8; font-size:13px; margin-top:6px}\n.report{\n  white-space:pre-wrap; background:#020617; border:1px solid #334155; border-radius:18px;\n  padding:16px; min-height:320px; max-height:78vh; overflow:auto; color:#e5e7eb;\n}\n.user-report{\n  border-color:#38bdf8;\n}\n.dev-report{\n  border-color:#f59e0b;\n  max-height:65vh;\n}\n.report-note{\n  color:#cbd5e1;\n  font-size:14px;\n  margin:8px 0 12px;\n}\n.copy-btn{\n  background:#1f2937;\n  color:#fff;\n  border:1px solid #475569;\n  margin-top:10px;\n}\n.copy-status{\n  color:#22c55e;\n  font-size:13px;\n  margin-top:6px;\n  min-height:22px;\n}\n.badge{\n  display:inline-block; padding:3px 10px; border-radius:999px; background:rgba(245,158,11,.14);\n  color:#fbbf24; border:1px solid rgba(245,158,11,.35); margin:3px; font-size:13px;\n}\n.footer{color:#94a3b8; text-align:center; font-size:13px; margin-top:18px}\n\ntable{width:100%; border-collapse:collapse; margin-top:10px}\nth,td{border-bottom:1px solid #334155; padding:7px; vertical-align:top}\nth{color:#fbbf24; font-size:13px}\ntd{font-size:13px}\n.checkbox-cell{text-align:center; width:48px}\n.small-input{min-width:105px}\n.note-input{min-width:150px}\n.axis-title{color:#38bdf8; font-weight:700; margin-top:8px}\n.error-box{\n  white-space:pre-wrap; background:#450a0a; border:1px solid #ef4444; border-radius:18px;\n  padding:14px; color:#fee2e2; margin-bottom:14px;\n}\n\n</style>\n\n<script>\nfunction copyReportText(boxId, statusId){\n  const box = document.getElementById(boxId);\n  const status = document.getElementById(statusId);\n  if(!box){ return; }\n\n  const text = box.innerText || box.textContent || "";\n  if(!text.trim()){\n    status.textContent = "لا يوجد تقرير لنسخه.";\n    return;\n  }\n\n  if(navigator.clipboard && window.isSecureContext){\n    navigator.clipboard.writeText(text).then(function(){\n      status.textContent = "تم نسخ التقرير.";\n    }).catch(function(){\n      fallbackCopy(text, status);\n    });\n  } else {\n    fallbackCopy(text, status);\n  }\n}\n\nfunction fallbackCopy(text, status){\n  const area = document.createElement("textarea");\n  area.value = text;\n  area.style.position = "fixed";\n  area.style.top = "-1000px";\n  area.style.right = "-1000px";\n  document.body.appendChild(area);\n  area.focus();\n  area.select();\n\n  try{\n    const ok = document.execCommand("copy");\n    status.textContent = ok ? "تم نسخ التقرير." : "لم ينجح النسخ تلقائيًا. اضغط مطولًا على التقرير وانسخه يدويًا.";\n  }catch(e){\n    status.textContent = "لم ينجح النسخ تلقائيًا. اضغط مطولًا على التقرير وانسخه يدويًا.";\n  }\n\n  document.body.removeChild(area);\n}\n</script>\n\n</head>\n<body>\n<div class="wrap">\n  <section class="hero">\n    <h1>تصحيح الطالع</h1>\n  </section>\n\n  {% if error %}\n  <section class="card">\n    <h2>تنبيه</h2>\n    <div class="error-box">{{ error }}</div>\n  </section>\n  {% endif %}\n\n  <form method="post">\n\n    <div class="grid">\n      <section class="card">\n        <div class="top-actions">\n          <button type="submit" name="action" value="clear" class="clear-btn" formnovalidate>مسح البيانات</button>\n          <a class="home-btn" href="/">العودة إلى الرئيسية</a>\n        </div>\n        <h2>بيانات الميلاد ومجال البحث</h2>\n\n        <label>الاسم</label>\n        <input name="name" value="{{ form.name }}">\n\n        <div class="row">\n          <div>\n            <label>الدولة</label>\n            <select id="rect_country" name="country" onchange="rectUpdateCities()">\n              <option value="">اختر الدولة</option>\n              {% for c in city_country_options %}\n              <option value="{{ c.code }}" {% if form.country == c.code %}selected{% endif %}>{{ c.name }}</option>\n              {% endfor %}\n            </select>\n          </div>\n          <div>\n            <label>المدينة</label>\n            <select id="rect_city" name="city" data-selected="{{ form.city }}" onchange="rectApplyCity()">\n              <option value="">اختر المدينة</option>\n            </select>\n          </div>\n        </div>\n\n        <input type="hidden" id="rect_preset" name="preset" value="{{ form.preset }}">\n        <input type="hidden" id="rect_lat" name="lat" value="{{ form.lat }}">\n        <input type="hidden" id="rect_lon" name="lon" value="{{ form.lon }}">\n\n        <div class="row">\n          <div>\n            <label>تاريخ الميلاد</label>\n            <input name="birth_date" type="date" value="{{ form.birth_date }}">\n          </div>\n          <div>\n            <label>فرق التوقيت وقت الولادة GMT</label>\n            <select id="rect_tz" name="tz">\n              <option value="">اختر فرق التوقيت</option>\n              {% for value, label in timezone_options %}\n              <option value="{{ value }}" {% if form.tz|string == value|string %}selected{% endif %}>{{ label }}</option>\n              {% endfor %}\n            </select>\n          </div>\n        </div>\n\n        <div class="row">\n          <div>\n            <label>بداية البحث</label>\n            <input name="start_time" type="time" value="{{ form.start_time }}">\n          </div>\n          <div>\n            <label>نهاية البحث</label>\n            <input name="end_time" type="time" value="{{ form.end_time }}">\n          </div>\n        </div>\n\n        <div class="hint">\n          إذا كان وقت الميلاد معلومًا أنه بعد 12 ظهرًا، اجعل بداية البحث 12:00 أو بعد ذلك.\n          التطبيق لا يستخدم الوقت التقريبي نفسيًا، بل يفحص فقط المجال الذي تحدده هنا.\n        </div>\n        <div class="hint">\n          إذا اخترت مدينة من القائمة، سيتم استخدام إحداثياتها وفارق توقيتها عند الضغط على استخراج.\n        </div>\n      </section>\n\n      <section class="card">\n        <h2>المحور الصحي</h2>\n        <div class="hint">\n          اختر الحالات الموجودة فقط. الحد الأدنى: حالة صحية واحدة على الأقل.\n        </div>\n\n        <div style="overflow:auto">\n        <table>\n          <thead>\n            <tr>\n              <th>موجود</th>\n              <th>الحالة الصحية</th>\n              <th>التاريخ</th>\n              <th>الدقة</th>\n              <th>الشدة</th>\n              <th>ملاحظة</th>\n            </tr>\n          </thead>\n          <tbody>\n          {% for row in form.health_rows %}\n            {% set i = loop.index0 %}\n            <tr>\n              <td class="checkbox-cell"><input type="checkbox" name="health_enabled_{{ i }}" {% if row.enabled %}checked{% endif %}></td>\n              <td>\n                <select name="health_type_{{ i }}">\n                  {% for opt in health_options %}\n                  <option value="{{ opt }}" {% if row.type == opt %}selected{% endif %}>{{ opt }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td><input class="small-input" name="health_date_{{ i }}" value="{{ row.date_text }}" placeholder="birth أو 1998-02-05"></td>\n              <td>\n                <select name="health_precision_{{ i }}">\n                  {% for val, label in precision_options %}\n                  <option value="{{ val }}" {% if row.precision == val %}selected{% endif %}>{{ label }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td>\n                <select name="health_severity_{{ i }}">\n                  {% for sev in severity_options %}\n                  <option value="{{ sev }}" {% if row.severity|string == sev|string %}selected{% endif %}>{{ sev }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td><input class="note-input" name="health_notes_{{ i }}" value="{{ row.notes }}"></td>\n            </tr>\n          {% endfor %}\n          </tbody>\n        </table>\n        </div>\n\n        <h2 style="margin-top:18px">محور الأحداث العميقة</h2>\n        <div class="hint">\n          اختر الأحداث الموجودة فقط. الحد الأدنى: حدثان عميقان على الأقل.\n        </div>\n\n        <div style="overflow:auto">\n        <table>\n          <thead>\n            <tr>\n              <th>موجود</th>\n              <th>الحدث</th>\n              <th>التاريخ</th>\n              <th>الدقة</th>\n              <th>الشدة</th>\n              <th>ملاحظة</th>\n            </tr>\n          </thead>\n          <tbody>\n          {% for row in form.event_rows %}\n            {% set i = loop.index0 %}\n            <tr>\n              <td class="checkbox-cell"><input type="checkbox" name="event_enabled_{{ i }}" {% if row.enabled %}checked{% endif %}></td>\n              <td>\n                <select name="event_type_{{ i }}">\n                  {% for opt in event_options %}\n                  <option value="{{ opt }}" {% if row.type == opt %}selected{% endif %}>{{ opt }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td><input class="small-input" name="event_date_{{ i }}" value="{{ row.date_text }}" placeholder="1998-02-05"></td>\n              <td>\n                <select name="event_precision_{{ i }}">\n                  {% for val, label in precision_options %}\n                  <option value="{{ val }}" {% if row.precision == val %}selected{% endif %}>{{ label }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td>\n                <select name="event_severity_{{ i }}">\n                  {% for sev in severity_options %}\n                  <option value="{{ sev }}" {% if row.severity|string == sev|string %}selected{% endif %}>{{ sev }}</option>\n                  {% endfor %}\n                </select>\n              </td>\n              <td><input class="note-input" name="event_notes_{{ i }}" value="{{ row.notes }}"></td>\n            </tr>\n          {% endfor %}\n          </tbody>\n        </table>\n        </div>\n      </section>\n\n      <section class="card">\n        <h2>كود تصحيح الطالع واستخراج النتائج</h2>\n        <div class="rect-code-box" style="margin-top:14px">\n          <label>كود تصحيح الطالع</label>\n          <input name="rect_code" value="{{ form.rect_code }}" placeholder="ضع الكود هنا قبل استخراج أفضل 5 أوقات">\n          <a class="copy-btn" style="display:block;text-align:center;text-decoration:none;margin-top:10px" href="{{ code_request_url }}" target="_blank">طلب كود تصحيح الطالع عبر تيليغرام</a>\n          <div class="hint">بعد إدخال بيانات الميلاد والمحور الصحي ومحور الأحداث، ضع الكود هنا ثم اضغط على زر استخراج أفضل 5 أوقات.</div>\n        </div>\n        <button type="submit" name="action" value="calculate">استخراج أفضل 5 أوقات</button>\n      </section>\n    </div>\n  </form>\n\n  <section class="card">\n    <h2>تقرير المستخدم</h2>\n    <div class="report-note">\n      تقرير مختصر بلغة بسيطة، مناسب للمستخدم العادي ولا يحتوي على التفاصيل الفلكية الفنية.\n    </div>\n    <div id="userReportBox" class="report user-report">{{ user_report or "هذا القسم غير مجاني. أدخل البيانات ثم ضع الكود الخاص واضغط استخراج أفضل 5 أوقات." }}</div>\n    <button type="button" class="copy-btn" onclick="copyReportText(\'userReportBox\',\'copyUserStatus\')">نسخ تقرير المستخدم</button>\n    <div id="copyUserStatus" class="copy-status"></div>\n  </section>\n\n\n\n\n</div>\n\n<script>\nfunction rectUpdateCities(){\n  const country = document.getElementById("rect_country");\n  const city = document.getElementById("rect_city");\n  if(!country || !city) return;\n  const selected = city.getAttribute("data-selected") || city.value || "";\n  city.innerHTML = `<option value="">جارٍ تحميل المدن...</option>`;\n  if(!country.value){\n    city.innerHTML = `<option value="">اختر المدينة</option>`;\n    return;\n  }\n  fetch(`/api/cities?country_code=${encodeURIComponent(country.value)}`)\n    .then(r => r.json())\n    .then(data => {\n      city.innerHTML = `<option value="">اختر المدينة</option>`;\n      (data.cities || []).forEach(function(name){\n        const opt = document.createElement("option");\n        opt.value = name;\n        opt.textContent = name;\n        if(name === selected){ opt.selected = true; }\n        city.appendChild(opt);\n      });\n    })\n    .catch(() => {\n      city.innerHTML = `<option value="">تعذر تحميل المدن</option>`;\n    });\n}\nfunction rectApplyCity(){\n  const preset = document.getElementById("rect_preset");\n  if(preset) preset.value = "";\n}\ndocument.addEventListener("DOMContentLoaded", function(){ rectUpdateCities(); });\n</script>\n</body>\n</html>\n"""\n\n\ndef default_form() -> dict:\n    return {\n        "name": "",\n        "country": "العراق",\n        "city": "الشامية",\n        "preset": "العراق - الشامية",\n        "birth_date": "1968-08-12",\n        "tz": "3",\n        "lat": "31.9640",\n        "lon": "44.6000",\n        "start_time": "12:00",\n        "end_time": "13:00",\n        "health_rows": make_empty_health_rows(8),\n        "event_rows": make_empty_event_rows(10),\n    }\n\n\ndef blank_form() -> dict:\n    return {\n        "name": "",\n        "country": "",\n        "city": "",\n        "preset": "",\n        "birth_date": "",\n        "tz": "",\n        "lat": "",\n        "lon": "",\n        "start_time": "",\n        "end_time": "",\n        "health_rows": make_blank_health_rows(8),\n        "event_rows": make_blank_event_rows(10),\n    }\n\n\ndef rectification_index():\n    form = blank_form()\n    user_report = ""\n    dev_report = ""\n    error = ""\n\n    if request.method == "POST":\n        action = request.form.get("action", "")\n\n        if action == "clear":\n            form = blank_form()\n            user_report = "تم مسح البيانات. أدخل بيانات حالة جديدة ثم اضغط استخراج أفضل 5 أوقات."\n            dev_report = ""\n            return render_template_string(\n                HTML,\n                form=form,\n                user_report=user_report,\n                dev_report=dev_report,\n                error=error,\n                presets=list(CITY_PRESETS.keys()),\n                city_country_options=rectification_country_options(),\n                city_presets_json=json.dumps(rectification_city_payload(), ensure_ascii=False),\n                timezone_options=rectification_timezone_options(),\n                health_options=HEALTH_OPTIONS,\n                event_options=EVENT_OPTIONS,\n                precision_options=PRECISION_OPTIONS,\n                severity_options=SEVERITY_OPTIONS,\n                code_request_url=telegram_contact_url("السلام عليكم، أريد طلب كود تصحيح الطالع في ASTROGATE."),\n            )\n\n        form.update({\n            "name": request.form.get("name", ""),\n            "country": request.form.get("country", ""),\n            "city": request.form.get("city", ""),\n            "preset": request.form.get("preset", ""),\n            "birth_date": request.form.get("birth_date", ""),\n            "tz": request.form.get("tz", "3"),\n            "lat": request.form.get("lat", ""),\n            "lon": request.form.get("lon", ""),\n            "start_time": request.form.get("start_time", "12:00"),\n            "end_time": request.form.get("end_time", "13:00"),\n            "health_rows": rows_from_form("health", 8, "health"),\n            "event_rows": rows_from_form("event", 10, "event"),\n            "rect_code": request.form.get("rect_code", ""),\n        })\n\n        try:\n            birth_date = datetime.strptime(form["birth_date"], "%Y-%m-%d")\n\n            if form["preset"] in CITY_PRESETS:\n                lat, lon, tz = CITY_PRESETS[form["preset"]]\n                form["lat"] = str(lat)\n                form["lon"] = str(lon)\n                form["tz"] = str(tz)\n            else:\n                city_info = find_city(form.get("country", ""), form.get("city", ""))\n                if not city_info:\n                    raise ValueError("لم أتمكن من تحديد المدينة. اختر الدولة والمدينة من القوائم بدقة.")\n                form["lat"] = str(city_info.get("lat", ""))\n                form["lon"] = str(city_info.get("lon", ""))\n                if not str(form.get("tz", "")).strip():\n                    tz_name = str(city_info.get("timezone", ""))\n                    form["tz"] = str(timezone_offset_for_birth(tz_name, birth_date.year, birth_date.month, birth_date.day, 12, 0))\n\n            lat = float(form["lat"])\n            lon = float(form["lon"])\n            tz = float(form["tz"])\n\n            health_items = selected_rows_to_items(form["health_rows"], "health")\n            event_items = selected_rows_to_items(form["event_rows"], "event")\n\n            validation_errors = validate_minimum_inputs(health_items, event_items, form["start_time"], form["end_time"])\n            if validation_errors:\n                raise ValueError("\\n".join(validation_errors))\n\n            ok_code, clean_code, code_msg = check_premium_code(form.get("rect_code", ""), "rectification")\n            if not ok_code:\n                raise ValueError(code_msg)\n\n            engine = RectificationEngine(birth_date=birth_date, lat=lat, lon=lon, tz_hours=tz)\n            all_results = engine.run_all(form["start_time"], form["end_time"], health_items, event_items)\n            results = all_results[:5]\n\n            meta = {\n                "name": form["name"],\n                "country": form["country"],\n                "city": form["city"],\n                "lat": lat,\n                "lon": lon,\n                "tz": tz,\n                "start_time": form["start_time"],\n                "end_time": form["end_time"],\n                "data_quality": data_quality_label(health_items, event_items),\n                "health_count": len(health_items),\n                "event_count": len(event_items),\n            }\n\n            user_report = build_user_report(results, meta, all_results=all_results)\n            dev_report = ""\n            if not is_master_code(clean_code):\n                mark_premium_code_used(clean_code, "rectification")\n\n        except Exception as e:\n            error = f"{type(e).__name__}: {e}"\n\n    return render_template_string(\n        HTML,\n        form=form,\n        user_report=user_report,\n        dev_report=dev_report,\n        error=error,\n        presets=list(CITY_PRESETS.keys()),\n        city_country_options=rectification_country_options(),\n        city_presets_json=json.dumps(rectification_city_payload(), ensure_ascii=False),\n        timezone_options=rectification_timezone_options(),\n        health_options=HEALTH_OPTIONS,\n        event_options=EVENT_OPTIONS,\n        precision_options=PRECISION_OPTIONS,\n        severity_options=SEVERITY_OPTIONS,\n                code_request_url=telegram_contact_url("السلام عليكم، أريد طلب كود تصحيح الطالع في ASTROGATE."),\n    )\n\n\n'
_RECTIFICATION_NAMESPACE = {
    "check_premium_code": check_premium_code,
    "mark_premium_code_used": mark_premium_code_used,
    "is_master_code": is_master_code,
    "telegram_contact_url": telegram_contact_url,
    "build_country_list": build_country_list,
    "find_city": find_city,
    "timezone_offset_for_birth": timezone_offset_for_birth,
}
exec(_RECTIFICATION_MODULE_CODE, _RECTIFICATION_NAMESPACE)

@app.route("/rectification", methods=["GET", "POST"])
def rectification():
    return _RECTIFICATION_NAMESPACE["rectification_index"]()

# ============================================================
